var COURSE_EL_PL = [{day: 1, title: `Χαιρετισμοί και πρώτες λέξεις`, title_native: `Powitania i pierwsze słowa`, focus: `Σήμερα μαθαίνεις πώς να χαιρετάς ευγενικά στην Πολωνία, είτε φτάνεις σε ξενοδοχείο στη Βαρσοβία είτε μπαίνεις σε ένα μικρό καφέ στην Κρακοβία. Ο στόχος είναι να νιώσεις άνετα με τις πρώτες καθημερινές λέξεις.`, vocab: [{pl: `dzień dobry`, el: `καλημέρα / καλησπέρα`, ipa: `τζεν ΝΤΟ-μπρι`},{pl: `cześć`, el: `γεια`, ipa: `τσεστς`},{pl: `dobry wieczór`, el: `καλησπέρα`, ipa: `ΝΤΟ-μπρι ΒΙΕ-τσουρ`},{pl: `do widzenia`, el: `αντίο`, ipa: `ντο βι-ΤΖΕ-νια`},{pl: `proszę`, el: `παρακαλώ`, ipa: `ΠΡΟ-σε`},{pl: `dziękuję`, el: `ευχαριστώ`, ipa: `τζεν-ΚΟΥ-γιε`},{pl: `tak`, el: `ναι`, ipa: `τακ`},{pl: `nie`, el: `όχι`, ipa: `νιε`},{pl: `przepraszam`, el: `συγγνώμη / με συγχωρείτε`, ipa: `πσε-ΠΡΑ-σαμ`},{pl: `Polska`, el: `Πολωνία`, ipa: `ΠΟΛ-σκα`}], phrases: [{pl: `Dzień dobry.`, el: `Καλημέρα.`, ipa: `τζεν ΝΤΟ-μπρι`},{pl: `Cześć!`, el: `Γεια!`, ipa: `τσεστς`},{pl: `Dziękuję bardzo.`, el: `Ευχαριστώ πολύ.`, ipa: `τζεν-ΚΟΥ-γιε ΜΠΑΡ-τζο`},{pl: `Przepraszam.`, el: `Με συγχωρείτε.`, ipa: `πσε-ΠΡΑ-σαμ`},{pl: `Do widzenia.`, el: `Αντίο.`, ipa: `ντο βι-ΤΖΕ-νια`},{pl: `Tak, proszę.`, el: `Ναι, παρακαλώ.`, ipa: `τακ ΠΡΟ-σε`}], grammar: `Στα πολωνικά, οι ευγενικοί χαιρετισμοί είναι πολύ σημαντικοί σε μαγαζιά, ξενοδοχεία και εστιατόρια. Το Dzień dobry χρησιμοποιείται τόσο το πρωί όσο και μεγάλο μέρος της ημέρας, ενώ το Cześć είναι πιο φιλικό και ανεπίσημο. Το proszę μπορεί να σημαίνει «παρακαλώ», αλλά και «ορίστε» όταν σου δίνουν κάτι. Για έναν ταξιδιώτη, το να ξεκινάς με Dzień dobry ανοίγει σχεδόν κάθε συζήτηση ευγενικά.`, practice: [`Πες στα πολωνικά «Καλημέρα» και «Ευχαριστώ πολύ».`,`Φαντάσου ότι μπαίνεις σε ένα καφέ στην Κρακοβία και χαιρετάς τον υπάλληλο.`,`Διάλεξε τη σωστή λέξη για «ναι»: tak ή nie.`,`Πες «Με συγχωρείτε» σαν να θέλεις να τραβήξεις την προσοχή κάποιου.`,`Κλείσε μια μικρή συνομιλία λέγοντας «Αντίο» στα πολωνικά.`]},{day: 2, title: `Συστάσεις και προσωπικές πληροφορίες`, title_native: `Przedstawianie się`, focus: `Σήμερα μαθαίνεις να λες ποιος είσαι και από πού έρχεσαι. Αυτό είναι χρήσιμο όταν γνωρίζεις κάποιον σε ξενώνα, σε τουριστική ξενάγηση ή σε ένα μπαρ στη Βαρσοβία.`, vocab: [{pl: `ja`, el: `εγώ`, ipa: `για`},{pl: `ty`, el: `εσύ`, ipa: `τι`},{pl: `jestem`, el: `είμαι`, ipa: `ΓΕΣ-τεμ`},{pl: `mam`, el: `έχω`, ipa: `μαμ`},{pl: `imię`, el: `όνομα`, ipa: `Ι-μιε`},{pl: `Grecja`, el: `Ελλάδα`, ipa: `ΓΚΡΕ-τσια`},{pl: `Grek`, el: `Έλληνας`, ipa: `γκρεκ`},{pl: `Greczynka`, el: `Ελληνίδα`, ipa: `γκρε-ΤΣΙΝ-κα`},{pl: `turysta`, el: `τουρίστας`, ipa: `του-ΡΙΣ-τα`},{pl: `miło`, el: `ευχάριστα`, ipa: `ΜΙ-ουο`}], phrases: [{pl: `Mam na imię Nikos.`, el: `Με λένε Νίκο.`, ipa: `μαμ να Ι-μιε ΝΙ-κος`},{pl: `Jestem z Grecji.`, el: `Είμαι από την Ελλάδα.`, ipa: `ΓΕΣ-τεμ ζ ΓΚΡΕ-τσι`},{pl: `Miło mi.`, el: `Χάρηκα.`, ipa: `ΜΙ-ουο μι`},{pl: `Jak masz na imię?`, el: `Πώς σε λένε;`, ipa: `γιακ μας να Ι-μιε`},{pl: `Jestem turystą.`, el: `Είμαι τουρίστας.`, ipa: `ΓΕΣ-τεμ του-ΡΙΣ-τομ`},{pl: `A ty?`, el: `Κι εσύ;`, ipa: `α τι`}], grammar: `Η φράση Mam na imię σημαίνει κυριολεκτικά «έχω για όνομα», αλλά χρησιμοποιείται όπως το ελληνικό «με λένε». Για να πεις από πού είσαι, χρησιμοποιείς Jestem z και μετά τη χώρα. Η λέξη z προφέρεται συχνά σαν σύντομο «ζ». Σε πιο ανεπίσημες γνωριμίες, το Miło mi είναι ένας φυσικός τρόπος να πεις «χάρηκα».`, practice: [`Πες «Με λένε Μαρία» χρησιμοποιώντας Mam na imię.`,`Πες «Είμαι από την Ελλάδα» στα πολωνικά.`,`Ρώτησε κάποιον «Πώς σε λένε;».`,`Απάντησε σε μια γνωριμία με «Χάρηκα».`,`Δημιούργησε έναν μικρό διάλογο δύο γραμμών με όνομα και χώρα.`]},{day: 3, title: `Αριθμοί από το 0 έως το 20`, title_native: `Liczby od 0 do 20`, focus: `Σήμερα μαθαίνεις τους βασικούς αριθμούς που θα χρειαστείς για τιμές, δωμάτια, εισιτήρια και ώρες. Στην Πολωνία, ακόμα και λίγοι αριθμοί βοηθούν πολύ σε αγορές και μετακινήσεις.`, vocab: [{pl: `zero`, el: `μηδέν`, ipa: `ΖΕ-ρο`},{pl: `jeden`, el: `ένα`, ipa: `ΓΕ-ντεν`},{pl: `dwa`, el: `δύο`, ipa: `ντβα`},{pl: `trzy`, el: `τρία`, ipa: `τσι`},{pl: `cztery`, el: `τέσσερα`, ipa: `ΤΣΤΕ-ρι`},{pl: `pięć`, el: `πέντε`, ipa: `πιεντς`},{pl: `sześć`, el: `έξι`, ipa: `σεστς`},{pl: `siedem`, el: `επτά`, ipa: `ΣΙΕ-ντεμ`},{pl: `osiem`, el: `οκτώ`, ipa: `Ο-σεμ`},{pl: `dziesięć`, el: `δέκα`, ipa: `ΤΖΕ-σιεντς`}], phrases: [{pl: `Jeden bilet, proszę.`, el: `Ένα εισιτήριο, παρακαλώ.`, ipa: `ΓΕ-ντεν ΜΠΙ-λετ ΠΡΟ-σε`},{pl: `Dwa bilety, proszę.`, el: `Δύο εισιτήρια, παρακαλώ.`, ipa: `ντβα μπι-ΛΕ-τι ΠΡΟ-σε`},{pl: `Ile kosztuje?`, el: `Πόσο κοστίζει;`, ipa: `Ι-λε κοστ-ΤΟΥ-γιε`},{pl: `To kosztuje pięć złotych.`, el: `Αυτό κοστίζει πέντε ζλότι.`, ipa: `το κοστ-ΤΟΥ-γιε πιεντς ΖΟΥΟ-τιχ`},{pl: `Mam trzy torby.`, el: `Έχω τρεις τσάντες.`, ipa: `μαμ τσι ΤΟΡ-μπι`},{pl: `Numer dziesięć.`, el: `Αριθμός δέκα.`, ipa: `ΝΟΥ-μερ ΤΖΕ-σιεντς`}], grammar: `Οι αριθμοί στα πολωνικά αλλάζουν μερικές φορές τη μορφή των λέξεων που ακολουθούν, αλλά για ταξίδι αρκεί αρχικά να τους αναγνωρίζεις και να τους χρησιμοποιείς απλά. Το złoty είναι το πολωνικό νόμισμα, και συχνά θα ακούσεις złote ή złotych μετά από αριθμούς. Μην ανησυχείς για όλες τις κλίσεις τώρα· οι βασικές φράσεις λειτουργούν πολύ καλά. Εξάσκησε ιδιαίτερα τα dwa, trzy και pięć, γιατί ακούγονται συχνά σε εισιτήρια και παραγγελίες.`, practice: [`Μέτρησε δυνατά από το zero έως το dziesięć.`,`Πες «Ένα εισιτήριο, παρακαλώ» στα πολωνικά.`,`Ρώτησε «Πόσο κοστίζει;».`,`Φαντάσου ότι αγοράζεις δύο εισιτήρια στο τραμ και πες τη σωστή φράση.`,`Άκουσε νοερά μια τιμή με pięć złotych και μετάφρασέ τη.`]},{day: 4, title: `Ευγένεια και βασικές ανάγκες`, title_native: `Uprzejmość i podstawowe potrzeby`, focus: `Σήμερα μαθαίνεις φράσεις που σε βοηθούν να ζητάς βοήθεια χωρίς πίεση. Είναι χρήσιμες σε σταθμούς, μουσεία και μικρά καταστήματα σε πόλεις όπως το Γκντανσκ ή το Βρότσλαβ.`, vocab: [{pl: `pomoc`, el: `βοήθεια`, ipa: `ΠΟ-μοτς`},{pl: `woda`, el: `νερό`, ipa: `ΒΟ-ντα`},{pl: `toaleta`, el: `τουαλέτα`, ipa: `τοα-ΛΕ-τα`},{pl: `telefon`, el: `τηλέφωνο`, ipa: `τε-ΛΕ-φον`},{pl: `internet`, el: `ίντερνετ`, ipa: `ΙΝ-τερ-νετ`},{pl: `mapa`, el: `χάρτης`, ipa: `ΜΑ-πα`},{pl: `adres`, el: `διεύθυνση`, ipa: `Α-ντρες`},{pl: `chwila`, el: `στιγμή`, ipa: `ΧΦΙ-λα`},{pl: `dobrze`, el: `καλά`, ipa: `ΝΤΟΜ-μπζε`},{pl: `źle`, el: `άσχημα / λάθος`, ipa: `ζλε`}], phrases: [{pl: `Potrzebuję pomocy.`, el: `Χρειάζομαι βοήθεια.`, ipa: `ποτ-σε-ΜΠΟΥ-γιε ΠΟ-μο-τσι`},{pl: `Gdzie jest toaleta?`, el: `Πού είναι η τουαλέτα;`, ipa: `γκτζιε γεστ τοα-ΛΕ-τα`},{pl: `Poproszę wodę.`, el: `Θα ήθελα νερό.`, ipa: `πο-ΠΡΟ-σε ΒΟ-ντε`},{pl: `Czy jest internet?`, el: `Υπάρχει ίντερνετ;`, ipa: `τσι γεστ ΙΝ-τερ-νετ`},{pl: `Proszę chwilę poczekać.`, el: `Παρακαλώ περιμένετε λίγο.`, ipa: `ΠΡΟ-σε ΧΦΙ-λε πο-ΤΣΕ-κατς`},{pl: `Wszystko dobrze.`, el: `Όλα καλά.`, ipa: `ΦΣΙΣΤ-κο ΝΤΟΜ-μπζε`}], grammar: `Το Potrzebuję σημαίνει «χρειάζομαι» και είναι πολύ πρακτικό γιατί μπορείς να το συνδυάσεις με πολλές λέξεις. Η ερώτηση Gdzie jest...? σημαίνει «Πού είναι...;» και είναι από τις πιο χρήσιμες δομές για ταξιδιώτες. Το Czy στην αρχή μιας πρότασης τη μετατρέπει συχνά σε ερώτηση τύπου «υπάρχει;» ή «είναι;». Μπορείς να επιβιώσεις σε πολλές καταστάσεις μόνο με Potrzebuję, Gdzie jest και Proszę.`, practice: [`Πες «Χρειάζομαι βοήθεια» στα πολωνικά.`,`Ρώτησε πού είναι η τουαλέτα.`,`Ζήτησε νερό με ευγενικό τρόπο.`,`Ρώτησε αν υπάρχει ίντερνετ.`,`Πες «Όλα καλά» σαν απάντηση σε κάποιον που σε ρωτά αν είσαι εντάξει.`]},{day: 5, title: `Ημέρες, ώρες και βασικός χρόνος`, title_native: `Dni, godziny i czas`, focus: `Σήμερα μαθαίνεις πώς να μιλάς για ημέρες και απλές ώρες. Αυτό είναι σημαντικό για κρατήσεις, ωράρια μουσείων και αναχωρήσεις τρένων στην Πολωνία.`, vocab: [{pl: `dzisiaj`, el: `σήμερα`, ipa: `ΤΖΙ-σαι`},{pl: `jutro`, el: `αύριο`, ipa: `ΓΟΥ-τρο`},{pl: `wczoraj`, el: `χθες`, ipa: `ΦΤΣΟ-ραι`},{pl: `rano`, el: `πρωί`, ipa: `ΡΑ-νο`},{pl: `wieczorem`, el: `το βράδυ`, ipa: `βιε-ΤΣΟ-ρεμ`},{pl: `godzina`, el: `ώρα`, ipa: `γκο-ΤΖΙ-να`},{pl: `poniedziałek`, el: `Δευτέρα`, ipa: `πονιε-ΤΖΙΑ-ουεκ`},{pl: `wtorek`, el: `Τρίτη`, ipa: `ΦΤΟ-ρεκ`},{pl: `sobota`, el: `Σάββατο`, ipa: `σο-ΜΠΟ-τα`},{pl: `niedziela`, el: `Κυριακή`, ipa: `νιε-ΤΖΕ-λα`}], phrases: [{pl: `Która godzina?`, el: `Τι ώρα είναι;`, ipa: `ΚΤΟΥ-ρα γκο-ΤΖΙ-να`},{pl: `Dzisiaj jest sobota.`, el: `Σήμερα είναι Σάββατο.`, ipa: `ΤΖΙ-σαι γεστ σο-ΜΠΟ-τα`},{pl: `Jutro rano.`, el: `Αύριο το πρωί.`, ipa: `ΓΟΥ-τρο ΡΑ-νο`},{pl: `Wieczorem mam rezerwację.`, el: `Το βράδυ έχω κράτηση.`, ipa: `βιε-ΤΣΟ-ρεμ μαμ ρε-ζερ-ΒΑ-τσιε`},{pl: `O której godzinie?`, el: `Τι ώρα;`, ipa: `ο ΚΤΟΥ-ρει γκο-ΤΖΙ-νιε`},{pl: `Do zobaczenia jutro.`, el: `Τα λέμε αύριο.`, ipa: `ντο ζο-μπα-ΤΣΕ-νια ΓΟΥ-τρο`}], grammar: `Για την ώρα, οι Πολωνοί χρησιμοποιούν συχνά τη λέξη godzina, αλλά στην καθημερινή ομιλία η ερώτηση Która godzina? είναι αρκετή. Το dzisiaj, jutro και wczoraj μπαίνουν εύκολα στην αρχή μιας πρότασης. Το rano σημαίνει «το πρωί», ενώ wieczorem σημαίνει «το βράδυ». Σε κρατήσεις, θα ακούσεις συχνά O której godzinie?, δηλαδή «σε ποια ώρα;».`, practice: [`Ρώτησε «Τι ώρα είναι;» στα πολωνικά.`,`Πες «Αύριο το πρωί».`,`Πες «Σήμερα είναι Σάββατο».`,`Φαντάσου ότι έχεις κράτηση το βράδυ και πες το στα πολωνικά.`,`Πες «Τα λέμε αύριο» σε έναν νέο γνωστό.`]},{day: 6, title: `Στο αεροδρόμιο και στην άφιξη`, title_native: `Na lotnisku i po przylocie`, focus: `Σήμερα μαθαίνεις λέξεις και φράσεις για την άφιξη σε πολωνικό αεροδρόμιο, όπως στο Chopin Airport της Βαρσοβίας. Θα μπορείς να ρωτήσεις για αποσκευές, ταξί και έξοδο.`, vocab: [{pl: `lotnisko`, el: `αεροδρόμιο`, ipa: `λοτ-ΝΙΣ-κο`},{pl: `bagaż`, el: `αποσκευή`, ipa: `ΜΠΑ-γκαζ`},{pl: `paszport`, el: `διαβατήριο`, ipa: `ΠΑΣ-πορτ`},{pl: `kontrola`, el: `έλεγχος`, ipa: `κον-ΤΡΟ-λα`},{pl: `wyjście`, el: `έξοδος`, ipa: `ΒΙΪ-στιε`},{pl: `przylot`, el: `άφιξη πτήσης`, ipa: `ΠΣΙ-λοτ`},{pl: `taksówka`, el: `ταξί`, ipa: `τακ-ΣΟΥΦ-κα`},{pl: `autobus`, el: `λεωφορείο`, ipa: `αου-ΤΟ-μπους`},{pl: `centrum`, el: `κέντρο`, ipa: `ΤΣΕΝ-τρουμ`},{pl: `terminal`, el: `τερματικός σταθμός`, ipa: `ΤΕΡ-μι-ναλ`}], phrases: [{pl: `Gdzie jest bagaż?`, el: `Πού είναι οι αποσκευές;`, ipa: `γκτζιε γεστ ΜΠΑ-γκαζ`},{pl: `Gdzie jest wyjście?`, el: `Πού είναι η έξοδος;`, ipa: `γκτζιε γεστ ΒΙΪ-στιε`},{pl: `Potrzebuję taksówki.`, el: `Χρειάζομαι ταξί.`, ipa: `ποτ-σε-ΜΠΟΥ-γιε τακ-ΣΟΥΦ-κι`},{pl: `Do centrum, proszę.`, el: `Στο κέντρο, παρακαλώ.`, ipa: `ντο ΤΣΕΝ-τρουμ ΠΡΟ-σε`},{pl: `Mam paszport.`, el: `Έχω διαβατήριο.`, ipa: `μαμ ΠΑΣ-πορτ`},{pl: `To mój bagaż.`, el: `Αυτή είναι η αποσκευή μου.`, ipa: `το μουι ΜΠΑ-γκαζ`}], grammar: `Η λέξη mój σημαίνει «δικός μου» για αρσενικά ουσιαστικά, όπως bagaż. Το Gdzie jest...? παραμένει πολύ χρήσιμο για χώρους στο αεροδρόμιο. Όταν λες Do centrum, proszę, δεν χρειάζεται πλήρης πρόταση· είναι φυσικός τρόπος να πεις στον οδηγό τον προορισμό σου. Σε επίσημους ελέγχους, μίλα απλά και καθαρά με λέξεις όπως paszport και bagaż.`, practice: [`Ρώτησε πού είναι η έξοδος.`,`Πες σε οδηγό ταξί «Στο κέντρο, παρακαλώ».`,`Πες «Αυτή είναι η αποσκευή μου».`,`Ρώτησε πού είναι οι αποσκευές.`,`Φτιάξε μια μικρή σκηνή άφιξης με τρεις πολωνικές φράσεις.`]},{day: 7, title: `Ξενοδοχείο και κράτηση`, title_native: `Hotel i rezerwacja`, focus: `Σήμερα μαθαίνεις πώς να κάνεις check-in σε ξενοδοχείο ή ξενώνα στην Πολωνία. Θα μπορείς να δώσεις το όνομά σου, να ζητήσεις δωμάτιο και να ρωτήσεις για πρωινό.`, vocab: [{pl: `hotel`, el: `ξενοδοχείο`, ipa: `ΧΟ-τελ`},{pl: `rezerwacja`, el: `κράτηση`, ipa: `ρε-ζερ-ΒΑ-τσια`},{pl: `pokój`, el: `δωμάτιο`, ipa: `ΠΟ-κουι`},{pl: `klucz`, el: `κλειδί`, ipa: `κλουτς`},{pl: `śniadanie`, el: `πρωινό`, ipa: `σνια-ΝΤΑ-νιε`},{pl: `recepcja`, el: `ρεσεψιόν`, ipa: `ρε-ΤΣΕΠ-τσια`},{pl: `paszport`, el: `διαβατήριο`, ipa: `ΠΑΣ-πορτ`},{pl: `noc`, el: `νύχτα`, ipa: `νοτς`},{pl: `łóżko`, el: `κρεβάτι`, ipa: `ΓΟΥΣ-κο`},{pl: `winda`, el: `ασανσέρ`, ipa: `ΒΙΝ-ντα`}], phrases: [{pl: `Mam rezerwację.`, el: `Έχω κράτηση.`, ipa: `μαμ ρε-ζερ-ΒΑ-τσιε`},{pl: `Na nazwisko Papadopoulos.`, el: `Στο όνομα Παπαδόπουλος.`, ipa: `να να-ΖΒΙΣ-κο Πα-πα-ΝΤΟ-που-λος`},{pl: `Poproszę klucz.`, el: `Θα ήθελα το κλειδί.`, ipa: `πο-ΠΡΟ-σε κλουτς`},{pl: `Czy śniadanie jest w cenie?`, el: `Είναι το πρωινό στην τιμή;`, ipa: `τσι σνια-ΝΤΑ-νιε γεστ φ ΤΣΕ-νιε`},{pl: `Gdzie jest winda?`, el: `Πού είναι το ασανσέρ;`, ipa: `γκτζιε γεστ ΒΙΝ-ντα`},{pl: `Pokój jest gotowy.`, el: `Το δωμάτιο είναι έτοιμο.`, ipa: `ΠΟ-κουι γεστ γκο-ΤΟ-βι`}], grammar: `Για να πεις ότι έχεις κάτι, χρησιμοποιείς Mam. Η φράση Na nazwisko σημαίνει «στο επίθετο» και χρησιμοποιείται πολύ συχνά σε κρατήσεις. Η ερώτηση Czy... jest w cenie? σημαίνει «είναι μέσα στην τιμή;». Είναι χρήσιμη όχι μόνο για πρωινό, αλλά και για αποσκευές, εισιτήρια ή υπηρεσίες.`, practice: [`Πες «Έχω κράτηση» στα πολωνικά.`,`Πες «Στο όνομα Παπαδόπουλος».`,`Ρώτησε αν το πρωινό είναι στην τιμή.`,`Ρώτησε πού είναι το ασανσέρ.`,`Φαντάσου ότι παίρνεις το κλειδί στη ρεσεψιόν και ζήτησέ το ευγενικά.`]},{day: 8, title: `Κατευθύνσεις στην πόλη`, title_native: `Kierunki w mieście`, focus: `Σήμερα μαθαίνεις να ζητάς και να καταλαβαίνεις βασικές οδηγίες μέσα στην πόλη. Αυτό θα σε βοηθήσει σε πλατείες, σταθμούς και παλιές πόλεις όπως το Stare Miasto στη Βαρσοβία.`, vocab: [{pl: `ulica`, el: `δρόμος`, ipa: `ου-ΛΙ-τσα`},{pl: `plac`, el: `πλατεία`, ipa: `πλατς`},{pl: `prawo`, el: `δεξιά`, ipa: `ΠΡΑ-βο`},{pl: `lewo`, el: `αριστερά`, ipa: `ΛΕ-βο`},{pl: `prosto`, el: `ευθεία`, ipa: `ΠΡΟΣ-το`},{pl: `blisko`, el: `κοντά`, ipa: `ΜΠΛΙΣ-κο`},{pl: `daleko`, el: `μακριά`, ipa: `ντα-ΛΕ-κο`},{pl: `most`, el: `γέφυρα`, ipa: `μοστ`},{pl: `stacja`, el: `σταθμός`, ipa: `ΣΤΑ-τσια`},{pl: `muzeum`, el: `μουσείο`, ipa: `μου-ΖΕ-ουμ`}], phrases: [{pl: `Gdzie jest muzeum?`, el: `Πού είναι το μουσείο;`, ipa: `γκτζιε γεστ μου-ΖΕ-ουμ`},{pl: `Proszę iść prosto.`, el: `Παρακαλώ πηγαίνετε ευθεία.`, ipa: `ΠΡΟ-σε ιστς ΠΡΟΣ-το`},{pl: `W prawo.`, el: `Δεξιά.`, ipa: `φ ΠΡΑ-βο`},{pl: `W lewo.`, el: `Αριστερά.`, ipa: `φ ΛΕ-βο`},{pl: `Czy to daleko?`, el: `Είναι μακριά;`, ipa: `τσι το ντα-ΛΕ-κο`},{pl: `To jest blisko.`, el: `Είναι κοντά.`, ipa: `το γεστ ΜΠΛΙΣ-κο`}], grammar: `Το iść σημαίνει «πηγαίνω με τα πόδια» και εμφανίζεται συχνά σε οδηγίες. Οι φράσεις w prawo και w lewo σημαίνουν «προς τα δεξιά» και «προς τα αριστερά». Το Czy to daleko? είναι απλή και χρήσιμη ερώτηση όταν δεν ξέρεις αν αξίζει να περπατήσεις. Οι Πολωνοί συχνά δίνουν οδηγίες με σύντομες φράσεις, γι’ αυτό εξασκήσου στο να αναγνωρίζεις λέξεις-κλειδιά.`, practice: [`Ρώτησε πού είναι το μουσείο.`,`Πες «Πηγαίνετε ευθεία» στα πολωνικά.`,`Πες «δεξιά» και «αριστερά».`,`Ρώτησε αν κάτι είναι μακριά.`,`Φαντάσου ότι ψάχνεις την κεντρική πλατεία και ζήτησε οδηγίες.`]},{day: 9, title: `Δημόσιες συγκοινωνίες`, title_native: `Transport publiczny`, focus: `Σήμερα μαθαίνεις λέξεις για τραμ, λεωφορεία και μετρό, που είναι πολύ χρήσιμα σε πόλεις όπως η Βαρσοβία και το Πόζναν. Θα μπορείς να αγοράσεις εισιτήριο και να ρωτήσεις για στάσεις.`, vocab: [{pl: `tramwaj`, el: `τραμ`, ipa: `ΤΡΑΜ-βαι`},{pl: `autobus`, el: `λεωφορείο`, ipa: `αου-ΤΟ-μπους`},{pl: `metro`, el: `μετρό`, ipa: `ΜΕ-τρο`},{pl: `bilet`, el: `εισιτήριο`, ipa: `ΜΠΙ-λετ`},{pl: `przystanek`, el: `στάση`, ipa: `πσι-ΣΤΑ-νεκ`},{pl: `dworzec`, el: `σταθμός τρένων`, ipa: `ΝΤΒΟ-ζετς`},{pl: `pociąg`, el: `τρένο`, ipa: `ΠΟ-τσιονγκ`},{pl: `linia`, el: `γραμμή`, ipa: `ΛΙ-νια`},{pl: `kierunek`, el: `κατεύθυνση`, ipa: `κιε-ΡΟΥ-νεκ`},{pl: `następny`, el: `επόμενος`, ipa: `να-ΣΤΕΜΠ-νι`}], phrases: [{pl: `Poproszę bilet.`, el: `Θα ήθελα ένα εισιτήριο.`, ipa: `πο-ΠΡΟ-σε ΜΠΙ-λετ`},{pl: `Gdzie jest przystanek?`, el: `Πού είναι η στάση;`, ipa: `γκτζιε γεστ πσι-ΣΤΑ-νεκ`},{pl: `Który tramwaj jedzie do centrum?`, el: `Ποιο τραμ πάει στο κέντρο;`, ipa: `ΚΤΟΥ-ρι ΤΡΑΜ-βαι ΓΕ-τζιε ντο ΤΣΕΝ-τρουμ`},{pl: `To następny przystanek.`, el: `Είναι η επόμενη στάση.`, ipa: `το να-ΣΤΕΜΠ-νι πσι-ΣΤΑ-νεκ`},{pl: `Czy ten bilet jest ważny?`, el: `Είναι έγκυρο αυτό το εισιτήριο;`, ipa: `τσι τεν ΜΠΙ-λετ γεστ ΒΑΖ-νι`},{pl: `Jadę metrem.`, el: `Πηγαίνω με μετρό.`, ipa: `ΓΙΑ-ντε ΜΕ-τρεμ`}], grammar: `Το jadę σημαίνει «πηγαίνω με μεταφορικό μέσο», σε αντίθεση με το idę που είναι «πηγαίνω με τα πόδια». Η φράση do centrum σημαίνει «προς το κέντρο» ή «στο κέντρο». Για ερωτήσεις με «ποιο», χρησιμοποιείς często Który για αρσενικές λέξεις όπως tramwaj. Μην προσπαθήσεις να μάθεις όλες τις μορφές τώρα· απομνημόνευσε τις φράσεις όπως είναι.`, practice: [`Ζήτησε ένα εισιτήριο στα πολωνικά.`,`Ρώτησε πού είναι η στάση.`,`Πες «Πηγαίνω με μετρό».`,`Ρώτησε ποιο τραμ πηγαίνει στο κέντρο.`,`Πες ότι η επόμενη στάση είναι αυτή που χρειάζεσαι.`]},{day: 10, title: `Καφέ και γρήγορη παραγγελία`, title_native: `Kawiarnia i szybkie zamówienie`, focus: `Σήμερα μαθαίνεις πώς να παραγγέλνεις σε καφέ στην Πολωνία. Θα εξασκηθείς σε καφέ, τσάι, γλυκά και ευγενικές φράσεις παραγγελίας.`, vocab: [{pl: `kawa`, el: `καφές`, ipa: `ΚΑ-βα`},{pl: `herbata`, el: `τσάι`, ipa: `χερ-ΜΠΑ-τα`},{pl: `mleko`, el: `γάλα`, ipa: `ΜΛΕ-κο`},{pl: `cukier`, el: `ζάχαρη`, ipa: `ΤΣΟΥ-κιερ`},{pl: `ciasto`, el: `κέικ / γλυκό`, ipa: `ΤΣΙΑΣ-το`},{pl: `kubek`, el: `κούπα`, ipa: `ΚΟΥ-μπεκ`},{pl: `filiżanka`, el: `φλιτζάνι`, ipa: `φι-λι-ΖΑΝ-κα`},{pl: `mały`, el: `μικρός`, ipa: `ΜΑ-ουι`},{pl: `duży`, el: `μεγάλος`, ipa: `ΝΤΟΥ-ζι`},{pl: `rachunek`, el: `λογαριασμός`, ipa: `ρα-ΧΟΥ-νεκ`}], phrases: [{pl: `Poproszę kawę.`, el: `Θα ήθελα έναν καφέ.`, ipa: `πο-ΠΡΟ-σε ΚΑ-βε`},{pl: `Z mlekiem, proszę.`, el: `Με γάλα, παρακαλώ.`, ipa: `ζ ΜΛΕ-κιεμ ΠΡΟ-σε`},{pl: `Bez cukru.`, el: `Χωρίς ζάχαρη.`, ipa: `μπες ΤΣΟΥ-κρου`},{pl: `Poproszę małą kawę.`, el: `Θα ήθελα μικρό καφέ.`, ipa: `πο-ΠΡΟ-σε ΜΑ-ουομ ΚΑ-βε`},{pl: `Czy macie ciasto?`, el: `Έχετε γλυκό;`, ipa: `τσι ΜΑ-τσιε ΤΣΙΑΣ-το`},{pl: `Rachunek, proszę.`, el: `Τον λογαριασμό, παρακαλώ.`, ipa: `ρα-ΧΟΥ-νεκ ΠΡΟ-σε`}], grammar: `Το Poproszę είναι ένας από τους πιο φυσικούς τρόπους να παραγγείλεις κάτι ευγενικά. Οι λέξεις z και bez σημαίνουν «με» και «χωρίς». Όταν λες bez cukru, η λέξη cukier αλλάζει σε cukru, αλλά μπορείς να μάθεις τη φράση ολόκληρη. Σε καφέ, το Rachunek, proszę είναι σύντομο και απολύτως φυσικό.`, practice: [`Παράγγειλε έναν καφέ στα πολωνικά.`,`Ζήτησε καφέ με γάλα.`,`Πες «χωρίς ζάχαρη».`,`Ρώτησε αν έχουν γλυκό.`,`Ζήτησε τον λογαριασμό ευγενικά.`]},{day: 11, title: `Στο εστιατόριο`, title_native: `W restauracji`, focus: `Σήμερα μαθαίνεις βασικές φράσεις για φαγητό σε πολωνικό εστιατόριο. Θα μπορείς να ζητήσεις τραπέζι, μενού, νερό και λογαριασμό.`, vocab: [{pl: `restauracja`, el: `εστιατόριο`, ipa: `ρε-σταου-ΡΑ-τσια`},{pl: `stolik`, el: `τραπέζι`, ipa: `ΣΤΟ-λικ`},{pl: `menu`, el: `μενού`, ipa: `ΜΕ-νου`},{pl: `zupa`, el: `σούπα`, ipa: `ΖΟΥ-πα`},{pl: `pierogi`, el: `πιερόγκι`, ipa: `πιε-ΡΟ-γκι`},{pl: `mięso`, el: `κρέας`, ipa: `ΜΙΕΝ-σο`},{pl: `ryba`, el: `ψάρι`, ipa: `ΡΙ-μπα`},{pl: `sałatka`, el: `σαλάτα`, ipa: `σα-ΒΑΤ-κα`},{pl: `deser`, el: `επιδόρπιο`, ipa: `ΝΤΕ-σερ`},{pl: `kelner`, el: `σερβιτόρος`, ipa: `ΚΕΛ-νερ`}], phrases: [{pl: `Stolik dla dwóch osób, proszę.`, el: `Τραπέζι για δύο άτομα, παρακαλώ.`, ipa: `ΣΤΟ-λικ ντλα ντβουχ Ο-σουμπ ΠΡΟ-σε`},{pl: `Poproszę menu.`, el: `Θα ήθελα το μενού.`, ipa: `πο-ΠΡΟ-σε ΜΕ-νου`},{pl: `Co pan poleca?`, el: `Τι προτείνετε;`, ipa: `τσο παν πο-ΛΕ-τσα`},{pl: `Poproszę pierogi.`, el: `Θα ήθελα πιερόγκι.`, ipa: `πο-ΠΡΟ-σε πιε-ΡΟ-γκι`},{pl: `Czy jest coś wegetariańskiego?`, el: `Υπάρχει κάτι χορτοφαγικό;`, ipa: `τσι γεστ τσος βε-γκε-τα-ριαΝ-σκιε-γκο`},{pl: `To było bardzo dobre.`, el: `Ήταν πολύ καλό.`, ipa: `το ΜΠΙ-ουο ΜΠΑΡ-τζο ΝΤΟΜ-μπρε`}], grammar: `Στα πολωνικά υπάρχει ευγενική διάκριση ανάμεσα σε pan για άνδρα και pani για γυναίκα, αντίστοιχη με «κύριε» και «κυρία». Σε εστιατόρια μπορείς να ρωτήσεις Co pan poleca? ή Co pani poleca? ανάλογα με τον σερβιτόρο. Το dla σημαίνει «για», όπως στη φράση dla dwóch osób. Τα pierogi είναι κλασικό πολωνικό πιάτο και αξίζει να ξέρεις τη λέξη.`, practice: [`Ζήτησε τραπέζι για δύο άτομα.`,`Ζήτησε το μενού.`,`Ρώτησε τον σερβιτόρο τι προτείνει.`,`Παράγγειλε pierogi.`,`Πες ότι το φαγητό ήταν πολύ καλό.`]},{day: 12, title: `Προτιμήσεις φαγητού και αλλεργίες`, title_native: `Preferencje jedzenia i alergie`, focus: `Σήμερα μαθαίνεις να μιλάς για διατροφικές ανάγκες, αλλεργίες και προτιμήσεις. Αυτό είναι ιδιαίτερα χρήσιμο όταν παραγγέλνεις σε εστιατόρια ή αγοράζεις φαγητό σε φούρνο.`, vocab: [{pl: `alergia`, el: `αλλεργία`, ipa: `α-ΛΕΡ-γκια`},{pl: `orzechy`, el: `ξηροί καρποί`, ipa: `ο-ΖΕ-χι`},{pl: `mleko`, el: `γάλα`, ipa: `ΜΛΕ-κο`},{pl: `gluten`, el: `γλουτένη`, ipa: `ΓΚΛΟΥ-τεν`},{pl: `wegetarianin`, el: `χορτοφάγος άνδρας`, ipa: `βε-γκε-τα-ΡΙΑ-νιν`},{pl: `wegetarianka`, el: `χορτοφάγος γυναίκα`, ipa: `βε-γκε-τα-ΡΙΑΝ-κα`},{pl: `ostry`, el: `πικάντικος`, ipa: `ΟΣ-τρι`},{pl: `słodki`, el: `γλυκός`, ipa: `ΣΒΟΤ-κι`},{pl: `słony`, el: `αλμυρός`, ipa: `ΣΒΟ-νι`},{pl: `bezpieczny`, el: `ασφαλής`, ipa: `μπεζ-ΠΙΕ-τσνι`}], phrases: [{pl: `Mam alergię na orzechy.`, el: `Έχω αλλεργία στους ξηρούς καρπούς.`, ipa: `μαμ α-ΛΕΡ-γκιε να ο-ΖΕ-χι`},{pl: `Bez glutenu, proszę.`, el: `Χωρίς γλουτένη, παρακαλώ.`, ipa: `μπες ΓΚΛΟΥ-τε-νου ΠΡΟ-σε`},{pl: `Nie jem mięsa.`, el: `Δεν τρώω κρέας.`, ipa: `νιε γεμ ΜΙΕΝ-σα`},{pl: `Czy to jest ostre?`, el: `Είναι πικάντικο αυτό;`, ipa: `τσι το γεστ ΟΣ-τρε`},{pl: `Czy to zawiera mleko?`, el: `Περιέχει γάλα αυτό;`, ipa: `τσι το ζα-ΒΙΕ-ρα ΜΛΕ-κο`},{pl: `To jest dla mnie ważne.`, el: `Αυτό είναι σημαντικό για μένα.`, ipa: `το γεστ ντλα ΜΝΙΕ ΒΑΖ-νε`}], grammar: `Το Nie jem σημαίνει «δεν τρώω» και είναι απλό εργαλείο για διατροφικές προτιμήσεις. Η δομή Mam alergię na... σημαίνει «έχω αλλεργία σε...». Με το bez μπορείς να ζητήσεις κάτι χωρίς συγκεκριμένο συστατικό. Όταν υπάρχει σοβαρή αλλεργία, πες To jest dla mnie ważne για να δείξεις ότι δεν είναι απλή προτίμηση.`, practice: [`Πες «Έχω αλλεργία στους ξηρούς καρπούς».`,`Ζήτησε κάτι χωρίς γλουτένη.`,`Πες «Δεν τρώω κρέας».`,`Ρώτησε αν ένα πιάτο είναι πικάντικο.`,`Ρώτησε αν κάτι περιέχει γάλα.`]},{day: 13, title: `Αγορές και τιμές`, title_native: `Zakupy i ceny`, focus: `Σήμερα μαθαίνεις να ρωτάς τιμές και να αγοράζεις μικρά πράγματα. Αυτό είναι χρήσιμο σε αγορές, περίπτερα, φούρνους και καταστήματα με σουβενίρ.`, vocab: [{pl: `sklep`, el: `κατάστημα`, ipa: `σκλεπ`},{pl: `cena`, el: `τιμή`, ipa: `ΤΣΕ-να`},{pl: `pieniądze`, el: `χρήματα`, ipa: `πιε-ΝΙΟΝ-τζε`},{pl: `karta`, el: `κάρτα`, ipa: `ΚΑΡ-τα`},{pl: `gotówka`, el: `μετρητά`, ipa: `γκο-ΤΟΥΦ-κα`},{pl: `paragon`, el: `απόδειξη`, ipa: `πα-ΡΑ-γκον`},{pl: `torba`, el: `τσάντα`, ipa: `ΤΟΡ-μπα`},{pl: `drogi`, el: `ακριβός`, ipa: `ΝΤΡΟ-γκι`},{pl: `tani`, el: `φθηνός`, ipa: `ΤΑ-νι`},{pl: `pamiątka`, el: `σουβενίρ`, ipa: `πα-ΜΙΟΝΤ-κα`}], phrases: [{pl: `Ile to kosztuje?`, el: `Πόσο κοστίζει αυτό;`, ipa: `Ι-λε το κοστ-ΤΟΥ-γιε`},{pl: `Czy mogę zapłacić kartą?`, el: `Μπορώ να πληρώσω με κάρτα;`, ipa: `τσι ΜΟ-γκε ζα-ΠΒΑ-τσιτς ΚΑΡ-τομ`},{pl: `Poproszę paragon.`, el: `Θα ήθελα απόδειξη.`, ipa: `πο-ΠΡΟ-σε πα-ΡΑ-γκον`},{pl: `Czy macie torbę?`, el: `Έχετε τσάντα;`, ipa: `τσι ΜΑ-τσιε ΤΟΡ-μπε`},{pl: `To za drogie.`, el: `Αυτό είναι πολύ ακριβό.`, ipa: `το ζα ΝΤΡΟ-γκιε`},{pl: `Wezmę to.`, el: `Θα πάρω αυτό.`, ipa: `ΒΕΖ-με το`}], grammar: `Η ερώτηση Czy mogę...? σημαίνει «Μπορώ να...;» και είναι πολύ πρακτική για ευγενικά αιτήματα. Το kartą σημαίνει «με κάρτα», ενώ gotówką σημαίνει «με μετρητά». Η φράση Wezmę to είναι φυσική όταν αποφασίζεις να αγοράσεις κάτι. Το za πριν από επίθετο σημαίνει «πολύ» με αρνητική έννοια, όπως za drogie.`, practice: [`Ρώτησε πόσο κοστίζει κάτι.`,`Ρώτησε αν μπορείς να πληρώσεις με κάρτα.`,`Ζήτησε απόδειξη.`,`Πες «Θα πάρω αυτό».`,`Πες ευγενικά ότι κάτι είναι πολύ ακριβό.`]},{day: 14, title: `Ρούχα και μεγέθη`, title_native: `Ubrania i rozmiary`, focus: `Σήμερα μαθαίνεις λέξεις για ρούχα και πώς να ζητάς μέγεθος σε κατάστημα. Είναι χρήσιμο αν ψωνίζεις σε εμπορικό κέντρο στη Βαρσοβία ή σε μικρή μπουτίκ στο Γκντανσκ.`, vocab: [{pl: `ubranie`, el: `ρούχο`, ipa: `ου-ΜΠΡΑ-νιε`},{pl: `koszula`, el: `πουκάμισο`, ipa: `κο-ΣΟΥ-λα`},{pl: `spodnie`, el: `παντελόνι`, ipa: `ΣΠΟΝΤ-νιε`},{pl: `sukienka`, el: `φόρεμα`, ipa: `σου-ΚΙΕΝ-κα`},{pl: `buty`, el: `παπούτσια`, ipa: `ΜΠΟΥ-τι`},{pl: `rozmiar`, el: `μέγεθος`, ipa: `ΡΟΖ-μιαρ`},{pl: `mały`, el: `μικρός`, ipa: `ΜΑ-ουι`},{pl: `średni`, el: `μεσαίος`, ipa: `ΣΡΕΝΤ-νι`},{pl: `duży`, el: `μεγάλος`, ipa: `ΝΤΟΥ-ζι`},{pl: `przymierzalnia`, el: `δοκιμαστήριο`, ipa: `πσι-μιε-ΖΑΛ-νια`}], phrases: [{pl: `Jaki to rozmiar?`, el: `Τι μέγεθος είναι αυτό;`, ipa: `ΓΙΑ-κι το ΡΟΖ-μιαρ`},{pl: `Czy macie większy rozmiar?`, el: `Έχετε μεγαλύτερο μέγεθος;`, ipa: `τσι ΜΑ-τσιε ΒΙΕΝΚ-σι ΡΟΖ-μιαρ`},{pl: `Czy mogę przymierzyć?`, el: `Μπορώ να το δοκιμάσω;`, ipa: `τσι ΜΟ-γκε πσι-ΜΙΕ-ζιτς`},{pl: `Gdzie jest przymierzalnia?`, el: `Πού είναι το δοκιμαστήριο;`, ipa: `γκτζιε γεστ πσι-μιε-ΖΑΛ-νια`},{pl: `Te buty są dobre.`, el: `Αυτά τα παπούτσια είναι καλά.`, ipa: `τε ΜΠΟΥ-τι σον ΝΤΟΜ-μπρε`},{pl: `Nie pasuje.`, el: `Δεν μου κάνει.`, ipa: `νιε πα-ΣΟΥ-γιε`}], grammar: `Το Czy mogę...? είναι ιδανικό για να ζητήσεις άδεια, όπως Czy mogę przymierzyć? Οι λέξεις mały, średni και duży σημαίνουν μικρό, μεσαίο και μεγάλο, αλλά αλλάζουν ανάλογα με το ουσιαστικό. Για ταξίδι, αρκεί να καταλαβαίνεις τη βασική έννοια. Το Nie pasuje σημαίνει «δεν ταιριάζει» ή «δεν μου κάνει» και είναι χρήσιμο σε δοκιμαστήριο.`, practice: [`Ρώτησε τι μέγεθος είναι ένα ρούχο.`,`Ζήτησε μεγαλύτερο μέγεθος.`,`Ρώτησε αν μπορείς να δοκιμάσεις κάτι.`,`Ρώτησε πού είναι το δοκιμαστήριο.`,`Πες ότι τα παπούτσια είναι καλά.`]},{day: 15, title: `Στο σούπερ μάρκετ`, title_native: `W supermarkecie`, focus: `Σήμερα μαθαίνεις βασικές λέξεις για τρόφιμα και αγορές στο σούπερ μάρκετ. Θα μπορείς να βρεις ψωμί, νερό, φρούτα και να πληρώσεις στο ταμείο.`, vocab: [{pl: `supermarket`, el: `σούπερ μάρκετ`, ipa: `σου-περ-ΜΑΡ-κετ`},{pl: `chleb`, el: `ψωμί`, ipa: `χλεπ`},{pl: `ser`, el: `τυρί`, ipa: `σερ`},{pl: `jajka`, el: `αυγά`, ipa: `ΓΙΑΪ-κα`},{pl: `owoce`, el: `φρούτα`, ipa: `ο-ΒΟ-τσε`},{pl: `warzywa`, el: `λαχανικά`, ipa: `βα-ΖΙ-βα`},{pl: `woda`, el: `νερό`, ipa: `ΒΟ-ντα`},{pl: `koszyk`, el: `καλάθι`, ipa: `ΚΟ-σικ`},{pl: `kasa`, el: `ταμείο`, ipa: `ΚΑ-σα`},{pl: `promocja`, el: `προσφορά`, ipa: `προ-ΜΟ-τσια`}], phrases: [{pl: `Gdzie jest chleb?`, el: `Πού είναι το ψωμί;`, ipa: `γκτζιε γεστ χλεπ`},{pl: `Poproszę torbę.`, el: `Θα ήθελα μια τσάντα.`, ipa: `πο-ΠΡΟ-σε ΤΟΡ-μπε`},{pl: `Czy to jest promocja?`, el: `Είναι σε προσφορά αυτό;`, ipa: `τσι το γεστ προ-ΜΟ-τσια`},{pl: `Płacę kartą.`, el: `Πληρώνω με κάρτα.`, ipa: `ΠΒΑ-τσε ΚΑΡ-τομ`},{pl: `Potrzebuję koszyka.`, el: `Χρειάζομαι καλάθι.`, ipa: `ποτ-σε-ΜΠΟΥ-γιε ΚΟ-σι-κα`},{pl: `To wszystko.`, el: `Αυτά είναι όλα.`, ipa: `το ΦΣΙΣΤ-κο`}], grammar: `Στο ταμείο, το To wszystko σημαίνει «αυτά είναι όλα» και είναι πολύ φυσική φράση. Το Płacę kartą σημαίνει «πληρώνω με κάρτα» και μπορείς να το χρησιμοποιήσεις σχεδόν παντού. Το Gdzie jest...? λειτουργεί και μέσα σε καταστήματα για να βρεις προϊόντα. Τα πολωνικά σούπερ μάρκετ συχνά έχουν self-checkout, αλλά οι ίδιες βασικές λέξεις παραμένουν χρήσιμες.`, practice: [`Ρώτησε πού είναι το ψωμί.`,`Πες ότι πληρώνεις με κάρτα.`,`Ζήτησε τσάντα.`,`Ρώτησε αν κάτι είναι σε προσφορά.`,`Πες «Αυτά είναι όλα» στο ταμείο.`]},{day: 16, title: `Στο φαρμακείο`, title_native: `W aptece`, focus: `Σήμερα μαθαίνεις πώς να ζητάς βασικά πράγματα σε φαρμακείο. Αυτό είναι σημαντικό για ταξίδια, ειδικά αν χρειαστείς παυσίπονο, επίδεσμο ή βοήθεια για μικρή αδιαθεσία.`, vocab: [{pl: `apteka`, el: `φαρμακείο`, ipa: `απ-ΤΕ-κα`},{pl: `lek`, el: `φάρμακο`, ipa: `λεκ`},{pl: `ból`, el: `πόνος`, ipa: `μπουλ`},{pl: `głowa`, el: `κεφάλι`, ipa: `ΓΚΒΟ-βα`},{pl: `brzuch`, el: `κοιλιά`, ipa: `μπζουχ`},{pl: `gardło`, el: `λαιμός`, ipa: `ΓΚΑΡΝΤ-βο`},{pl: `tabletki`, el: `χάπια`, ipa: `τα-ΜΠΛΕΤ-κι`},{pl: `plaster`, el: `επίδεσμος / τσιρότο`, ipa: `ΠΛΑΣ-τερ`},{pl: `recepta`, el: `συνταγή`, ipa: `ρε-ΤΣΕΠ-τα`},{pl: `gorączka`, el: `πυρετός`, ipa: `γκο-ΡΟΝΤΣ-κα`}], phrases: [{pl: `Boli mnie głowa.`, el: `Με πονάει το κεφάλι.`, ipa: `ΜΠΟ-λι μνιε ΓΚΒΟ-βα`},{pl: `Boli mnie brzuch.`, el: `Με πονάει η κοιλιά.`, ipa: `ΜΠΟ-λι μνιε μπζουχ`},{pl: `Mam gorączkę.`, el: `Έχω πυρετό.`, ipa: `μαμ γκο-ΡΟΝΤΣ-κε`},{pl: `Potrzebuję tabletek.`, el: `Χρειάζομαι χάπια.`, ipa: `ποτ-σε-ΜΠΟΥ-γιε τα-ΜΠΛΕΤ-εκ`},{pl: `Czy potrzebuję recepty?`, el: `Χρειάζομαι συνταγή;`, ipa: `τσι ποτ-σε-ΜΠΟΥ-γιε ρε-ΤΣΕΠ-τι`},{pl: `Poproszę plastry.`, el: `Θα ήθελα τσιρότα.`, ipa: `πο-ΠΡΟ-σε ΠΛΑΣ-τρι`}], grammar: `Η φράση Boli mnie... σημαίνει «με πονάει...» και μετά βάζεις το μέρος του σώματος. Το Mam gorączkę σημαίνει «έχω πυρετό». Στα φαρμακεία στην Πολωνία, πολλά φάρμακα μπορεί να χρειάζονται recepta, δηλαδή συνταγή. Μίλα απλά και δείξε το σημείο που πονάει αν χρειαστεί.`, practice: [`Πες ότι σε πονάει το κεφάλι.`,`Πες ότι έχεις πυρετό.`,`Ζήτησε χάπια.`,`Ρώτησε αν χρειάζεσαι συνταγή.`,`Ζήτησε τσιρότα.`]},{day: 17, title: `Υγεία και έκτακτη ανάγκη`, title_native: `Zdrowie i nagły wypadek`, focus: `Σήμερα μαθαίνεις φράσεις για πιο σοβαρές καταστάσεις υγείας ή έκτακτης ανάγκης. Αυτές οι λέξεις είναι χρήσιμες σε ξενοδοχείο, δρόμο ή νοσοκομείο.`, vocab: [{pl: `lekarz`, el: `γιατρός`, ipa: `ΛΕ-καζ`},{pl: `szpital`, el: `νοσοκομείο`, ipa: `ΣΠΙ-ταλ`},{pl: `pomoc`, el: `βοήθεια`, ipa: `ΠΟ-μοτς`},{pl: `policja`, el: `αστυνομία`, ipa: `πο-ΛΙ-τσια`},{pl: `wypadek`, el: `ατύχημα`, ipa: `βι-ΠΑ-ντεκ`},{pl: `karetka`, el: `ασθενοφόρο`, ipa: `κα-ΡΕΤ-κα`},{pl: `ból`, el: `πόνος`, ipa: `μπουλ`},{pl: `chory`, el: `άρρωστος`, ipa: `ΧΟ-ρι`},{pl: `pilne`, el: `επείγον`, ipa: `ΠΙΛ-νε`},{pl: `adres`, el: `διεύθυνση`, ipa: `Α-ντρες`}], phrases: [{pl: `Potrzebuję lekarza.`, el: `Χρειάζομαι γιατρό.`, ipa: `ποτ-σε-ΜΠΟΥ-γιε ΛΕ-κα-ζα`},{pl: `Proszę wezwać karetkę.`, el: `Καλέστε ασθενοφόρο, παρακαλώ.`, ipa: `ΠΡΟ-σε ΒΕΖ-βατς κα-ΡΕΤ-κε`},{pl: `To pilne.`, el: `Είναι επείγον.`, ipa: `το ΠΙΛ-νε`},{pl: `Gdzie jest szpital?`, el: `Πού είναι το νοσοκομείο;`, ipa: `γκτζιε γεστ ΣΠΙ-ταλ`},{pl: `Nie czuję się dobrze.`, el: `Δεν νιώθω καλά.`, ipa: `νιε ΤΣΟΥ-γιε σιε ΝΤΟΜ-μπζε`},{pl: `Proszę zadzwonić na policję.`, el: `Καλέστε την αστυνομία, παρακαλώ.`, ipa: `ΠΡΟ-σε ζαντ-ΖΒΟ-νιτς να πο-ΛΙ-τσιε`}], grammar: `Το Proszę με ρήμα σε απαρέμφατο μπορεί να λειτουργήσει σαν ευγενική εντολή, όπως Proszę wezwać. Η φράση Nie czuję się dobrze είναι πιο γενική και σημαίνει «δεν νιώθω καλά». Σε επείγουσα κατάσταση, σύντομες φράσεις όπως To pilne είναι πιο χρήσιμες από μεγάλες προτάσεις. Κράτησε αυτές τις φράσεις έτοιμες στο κινητό σου όταν ταξιδεύεις.`, practice: [`Πες «Χρειάζομαι γιατρό».`,`Ζήτησε να καλέσουν ασθενοφόρο.`,`Πες ότι είναι επείγον.`,`Ρώτησε πού είναι το νοσοκομείο.`,`Πες ότι δεν νιώθεις καλά.`]},{day: 18, title: `Καιρός και ρούχα για την ημέρα`, title_native: `Pogoda i ubranie na dzień`, focus: `Σήμερα μαθαίνεις να μιλάς για τον καιρό, κάτι πολύ χρήσιμο στην Πολωνία όπου ο καιρός αλλάζει συχνά. Θα μπορείς να καταλάβεις αν χρειάζεσαι ομπρέλα, μπουφάν ή πιο ζεστά ρούχα.`, vocab: [{pl: `pogoda`, el: `καιρός`, ipa: `πο-ΓΚΟ-ντα`},{pl: `deszcz`, el: `βροχή`, ipa: `ντεστς`},{pl: `śnieg`, el: `χιόνι`, ipa: `σνιεγκ`},{pl: `słońce`, el: `ήλιος`, ipa: `ΣΒΟΝ-τσε`},{pl: `wiatr`, el: `άνεμος`, ipa: `βιατρ`},{pl: `zimno`, el: `κρύο`, ipa: `ΖΙΜ-νο`},{pl: `ciepło`, el: `ζέστη / ζεστά`, ipa: `ΤΣΙΕΠ-βο`},{pl: `parasol`, el: `ομπρέλα`, ipa: `πα-ΡΑ-σολ`},{pl: `kurtka`, el: `μπουφάν`, ipa: `ΚΟΥΡΤ-κα`},{pl: `buty`, el: `παπούτσια`, ipa: `ΜΠΟΥ-τι`}], phrases: [{pl: `Jaka jest pogoda?`, el: `Τι καιρό κάνει;`, ipa: `ΓΙΑ-κα γεστ πο-ΓΚΟ-ντα`},{pl: `Pada deszcz.`, el: `Βρέχει.`, ipa: `ΠΑ-ντα ντεστς`},{pl: `Jest zimno.`, el: `Κάνει κρύο.`, ipa: `γεστ ΖΙΜ-νο`},{pl: `Jest ciepło.`, el: `Κάνει ζέστη.`, ipa: `γεστ ΤΣΙΕΠ-βο`},{pl: `Potrzebuję parasola.`, el: `Χρειάζομαι ομπρέλα.`, ipa: `ποτ-σε-ΜΠΟΥ-γιε πα-ΡΑ-σο-λα`},{pl: `Dzisiaj jest słonecznie.`, el: `Σήμερα έχει ήλιο.`, ipa: `ΤΖΙ-σαι γεστ σβο-ΝΕΤΣ-νιε`}], grammar: `Για τον καιρό, τα πολωνικά χρησιμοποιούν συχνά απλές απρόσωπες φράσεις όπως Jest zimno ή Pada deszcz. Το pada σημαίνει «πέφτει», αλλά στην πράξη Pada deszcz σημαίνει «βρέχει». Το Potrzebuję parasola χρησιμοποιεί τη μορφή parasola μετά το potrzebuję. Μπορείς να μάθεις τη φράση ως έτοιμο κομμάτι για ταξίδι.`, practice: [`Ρώτησε τι καιρό κάνει.`,`Πες ότι βρέχει.`,`Πες ότι κάνει κρύο.`,`Πες ότι χρειάζεσαι ομπρέλα.`,`Πες ότι σήμερα έχει ήλιο.`]},{day: 19, title: `Τηλέφωνο, Wi-Fi και τεχνολογία`, title_native: `Telefon, Wi-Fi i technologia`, focus: `Σήμερα μαθαίνεις φράσεις για σύνδεση, φόρτιση και χρήση κινητού. Αυτό είναι απαραίτητο σε ξενοδοχεία, καφέ, σταθμούς και δημόσιους χώρους στην Πολωνία.`, vocab: [{pl: `telefon`, el: `τηλέφωνο`, ipa: `τε-ΛΕ-φον`},{pl: `ładowarka`, el: `φορτιστής`, ipa: `βα-ντο-ΒΑΡ-κα`},{pl: `bateria`, el: `μπαταρία`, ipa: `μπα-ΤΕΡ-ια`},{pl: `hasło`, el: `κωδικός`, ipa: `ΧΑΣ-βο`},{pl: `Wi-Fi`, el: `Wi-Fi`, ipa: `ΒΑΪ-φάι`},{pl: `internet`, el: `ίντερνετ`, ipa: `ΙΝ-τερ-νετ`},{pl: `gniazdko`, el: `πρίζα`, ipa: `ΓΝΙΑΣΤ-κο`},{pl: `ekran`, el: `οθόνη`, ipa: `ΕΚ-ραν`},{pl: `numer`, el: `αριθμός`, ipa: `ΝΟΥ-μερ`},{pl: `aplikacja`, el: `εφαρμογή`, ipa: `απ-λι-ΚΑ-τσια`}], phrases: [{pl: `Czy jest Wi-Fi?`, el: `Υπάρχει Wi-Fi;`, ipa: `τσι γεστ ΒΑΪ-φάι`},{pl: `Jakie jest hasło?`, el: `Ποιος είναι ο κωδικός;`, ipa: `ΓΙΑ-κιε γεστ ΧΑΣ-βο`},{pl: `Potrzebuję ładowarki.`, el: `Χρειάζομαι φορτιστή.`, ipa: `ποτ-σε-ΜΠΟΥ-γιε βα-ντο-ΒΑΡ-κι`},{pl: `Gdzie jest gniazdko?`, el: `Πού είναι η πρίζα;`, ipa: `γκτζιε γεστ ΓΝΙΑΣΤ-κο`},{pl: `Nie mam baterii.`, el: `Δεν έχω μπαταρία.`, ipa: `νιε μαμ μπα-ΤΕΡ-ι`},{pl: `Mój telefon nie działa.`, el: `Το τηλέφωνό μου δεν λειτουργεί.`, ipa: `μουι τε-ΛΕ-φον νιε ΤΖΙΑ-βα`}], grammar: `Η λέξη działa σημαίνει «λειτουργεί». Με το nie μπροστά, φτιάχνεις άρνηση: nie działa. Το Jakie jest hasło? είναι η πιο συνηθισμένη ερώτηση για κωδικό Wi-Fi. Το mój σημαίνει «δικός μου» και χρησιμοποιείται εδώ με το telefon. Σε πρακτικές καταστάσεις, μια απλή πρόταση με nie είναι αρκετή για να εξηγήσεις το πρόβλημα.`, practice: [`Ρώτησε αν υπάρχει Wi-Fi.`,`Ρώτησε ποιος είναι ο κωδικός.`,`Πες ότι χρειάζεσαι φορτιστή.`,`Ρώτησε πού είναι η πρίζα.`,`Πες ότι το τηλέφωνό σου δεν λειτουργεί.`]},{day: 20, title: `Στο μουσείο και σε αξιοθέατα`, title_native: `W muzeum i przy atrakcjach`, focus: `Σήμερα μαθαίνεις λέξεις για μουσεία, εισιτήρια και αξιοθέατα. Αυτό είναι χρήσιμο όταν επισκέπτεσαι το Βασιλικό Κάστρο στη Βαρσοβία ή μουσεία στην Κρακοβία.`, vocab: [{pl: `muzeum`, el: `μουσείο`, ipa: `μου-ΖΕ-ουμ`},{pl: `zamek`, el: `κάστρο`, ipa: `ΖΑ-μεκ`},{pl: `bilet`, el: `εισιτήριο`, ipa: `ΜΠΙ-λετ`},{pl: `wystawa`, el: `έκθεση`, ipa: `βι-ΣΤΑ-βα`},{pl: `wejście`, el: `είσοδος`, ipa: `ΒΕΪ-στιε`},{pl: `wyjście`, el: `έξοδος`, ipa: `ΒΙΪ-στιε`},{pl: `przewodnik`, el: `ξεναγός / οδηγός`, ipa: `πσε-ΒΟΝΤ-νικ`},{pl: `zdjęcie`, el: `φωτογραφία`, ipa: `ΖΝΤΖΕΝ-τσιε`},{pl: `zakaz`, el: `απαγόρευση`, ipa: `ΖΑ-κας`},{pl: `otwarte`, el: `ανοιχτό`, ipa: `ο-ΤΦΑΡ-τε`}], phrases: [{pl: `Poproszę bilet normalny.`, el: `Θα ήθελα κανονικό εισιτήριο.`, ipa: `πο-ΠΡΟ-σε ΜΠΙ-λετ νορ-ΜΑΛ-νι`},{pl: `Czy można robić zdjęcia?`, el: `Μπορούμε να βγάζουμε φωτογραφίες;`, ipa: `τσι ΜΟΖ-να ΡΟ-μπιτς ΖΝΤΖΕΝ-τσια`},{pl: `O której zamykacie?`, el: `Τι ώρα κλείνετε;`, ipa: `ο ΚΤΟΥ-ρει ζα-μι-ΚΑ-τσιε`},{pl: `Gdzie jest wejście?`, el: `Πού είναι η είσοδος;`, ipa: `γκτζιε γεστ ΒΕΪ-στιε`},{pl: `Czy jest przewodnik po angielsku?`, el: `Υπάρχει ξεναγός στα αγγλικά;`, ipa: `τσι γεστ πσε-ΒΟΝΤ-νικ πο αν-ΓΚΙΕΛ-σκου`},{pl: `To jest bardzo piękne.`, el: `Αυτό είναι πολύ όμορφο.`, ipa: `το γεστ ΜΠΑΡ-τζο ΠΙΕΝΚ-νε`}], grammar: `Το Czy można...? σημαίνει «επιτρέπεται;» ή «μπορεί κανείς;» και είναι πολύ χρήσιμο σε μουσεία. Η φράση robić zdjęcia σημαίνει «βγάζω φωτογραφίες». Το po angielsku σημαίνει «στα αγγλικά», ενώ po polsku σημαίνει «στα πολωνικά». Όταν ρωτάς για άδεια, το Czy można είναι πιο ουδέτερο και ευγενικό.`, practice: [`Ζήτησε ένα κανονικό εισιτήριο.`,`Ρώτησε αν επιτρέπονται φωτογραφίες.`,`Ρώτησε τι ώρα κλείνει το μουσείο.`,`Ρώτησε αν υπάρχει ξεναγός στα αγγλικά.`,`Πες ότι κάτι είναι πολύ όμορφο.`]},{day: 21, title: `Κοινωνικές φράσεις και μικρή κουβέντα`, title_native: `Zwroty społeczne i small talk`, focus: `Σήμερα μαθαίνεις πώς να κάνεις μικρή κουβέντα με ντόπιους ή άλλους ταξιδιώτες. Θα μπορείς να μιλήσεις για την πόλη, το ταξίδι και απλές εντυπώσεις.`, vocab: [{pl: `miasto`, el: `πόλη`, ipa: `ΜΙΑΣ-το`},{pl: `ładny`, el: `όμορφος`, ipa: `ΒΑΝΤ-νι`},{pl: `ciekawy`, el: `ενδιαφέρων`, ipa: `τσιε-ΚΑ-βι`},{pl: `podróż`, el: `ταξίδι`, ipa: `ΠΟ-ντρουζ`},{pl: `wakacje`, el: `διακοπές`, ipa: `βα-ΚΑ-τσιε`},{pl: `ludzie`, el: `άνθρωποι`, ipa: `ΛΟΥ-τζιε`},{pl: `lokalny`, el: `ντόπιος / τοπικός`, ipa: `λο-ΚΑΛ-νι`},{pl: `spokojny`, el: `ήρεμος`, ipa: `σπο-ΚΟΪ-νι`},{pl: `głośny`, el: `θορυβώδης`, ipa: `ΓΚΒΟΣ-νι`},{pl: `przyjemny`, el: `ευχάριστος`, ipa: `πσι-ΓΕΜ-νι`}], phrases: [{pl: `To miasto jest piękne.`, el: `Αυτή η πόλη είναι όμορφη.`, ipa: `το ΜΙΑΣ-το γεστ ΠΙΕΝΚ-νε`},{pl: `Podoba mi się Polska.`, el: `Μου αρέσει η Πολωνία.`, ipa: `πο-ΝΤΟ-μπα μι σιε ΠΟΛ-σκα`},{pl: `Jestem tu pierwszy raz.`, el: `Είμαι εδώ πρώτη φορά.`, ipa: `ΓΕΣ-τεμ του ΠΙΕΡΦ-σι ρας`},{pl: `Skąd jesteś?`, el: `Από πού είσαι;`, ipa: `σκοντ ΓΕΣ-τες`},{pl: `Jak długo tu mieszkasz?`, el: `Πόσο καιρό μένεις εδώ;`, ipa: `γιακ ΝΤΒΟΥ-γκο του ΜΙΕΣΚ-ας`},{pl: `Miło było porozmawiać.`, el: `Χάρηκα που μιλήσαμε.`, ipa: `ΜΙ-ουο ΜΠΙ-ουο πο-ροζ-ΜΑ-βιατς`}], grammar: `Η φράση Podoba mi się... σημαίνει «μου αρέσει...», αλλά η δομή είναι διαφορετική από τα ελληνικά. Μπορείς να πεις Podoba mi się Kraków ή Podoba mi się Polska. Το Skąd jesteś? είναι ανεπίσημο και ταιριάζει σε φιλική κουβέντα. Σε πιο επίσημο πλαίσιο, μπορείς να χρησιμοποιήσεις Skąd pan jest? ή Skąd pani jest?`, practice: [`Πες ότι η πόλη είναι όμορφη.`,`Πες ότι σου αρέσει η Πολωνία.`,`Πες ότι είσαι εδώ πρώτη φορά.`,`Ρώτησε κάποιον από πού είναι.`,`Κλείσε τη συζήτηση λέγοντας ότι χάρηκες που μιλήσατε.`]},{day: 22, title: `Προσκλήσεις και σχέδια`, title_native: `Zaproszenia i plany`, focus: `Σήμερα μαθαίνεις πώς να κάνεις απλά σχέδια με άλλους ανθρώπους. Αυτό είναι χρήσιμο αν γνωρίσεις κάποιον σε hostel, ξενάγηση ή καφέ και θέλετε να πάτε κάπου μαζί.`, vocab: [{pl: `plan`, el: `σχέδιο`, ipa: `πλαν`},{pl: `spotkanie`, el: `συνάντηση`, ipa: `σποτ-ΚΑ-νιε`},{pl: `kawiarnia`, el: `καφέ`, ipa: `κα-ΒΙΑΡ-νια`},{pl: `restauracja`, el: `εστιατόριο`, ipa: `ρε-σταου-ΡΑ-τσια`},{pl: `kino`, el: `σινεμά`, ipa: `ΚΙ-νο`},{pl: `park`, el: `πάρκο`, ipa: `παρκ`},{pl: `dzisiaj`, el: `σήμερα`, ipa: `ΤΖΙ-σαι`},{pl: `jutro`, el: `αύριο`, ipa: `ΓΟΥ-τρο`},{pl: `razem`, el: `μαζί`, ipa: `ΡΑ-ζεμ`},{pl: `czas`, el: `χρόνος`, ipa: `τσας`}], phrases: [{pl: `Masz czas?`, el: `Έχεις χρόνο;`, ipa: `μας τσας`},{pl: `Chcesz iść na kawę?`, el: `Θέλεις να πάμε για καφέ;`, ipa: `χτσες ιστς να ΚΑ-βε`},{pl: `Może jutro?`, el: `Ίσως αύριο;`, ipa: `ΜΟ-ζε ΓΟΥ-τρο`},{pl: `Idziemy razem?`, el: `Πάμε μαζί;`, ipa: `ι-ΤΖΕ-μι ΡΑ-ζεμ`},{pl: `O której się spotkamy?`, el: `Τι ώρα θα συναντηθούμε;`, ipa: `ο ΚΤΟΥ-ρει σιε σποτ-ΚΑ-μι`},{pl: `Brzmi dobrze.`, el: `Ακούγεται καλό.`, ipa: `μπζμι ΝΤΟΜ-μπζε`}], grammar: `Το chcesz σημαίνει «θέλεις» σε ανεπίσημο τόνο. Η φράση iść na kawę σημαίνει «πάω για καφέ». Το może σημαίνει «ίσως» ή «μήπως», και χρησιμοποιείται πολύ σε προτάσεις όπως Może jutro? Το Brzmi dobrze είναι φυσικός τρόπος να αποδεχτείς μια ιδέα.`, practice: [`Ρώτησε κάποιον αν έχει χρόνο.`,`Πρότεινε να πάτε για καφέ.`,`Πες «Ίσως αύριο».`,`Ρώτησε τι ώρα θα συναντηθείτε.`,`Απάντησε «Ακούγεται καλό».`]},{day: 23, title: `Στο ταξί και στις εφαρμογές μετακίνησης`, title_native: `Taksówka i aplikacje transportowe`, focus: `Σήμερα μαθαίνεις φράσεις για ταξί και διαδρομές με εφαρμογές. Θα μπορείς να πεις προορισμό, να ρωτήσεις τιμή και να εξηγήσεις πού θέλεις να σταματήσεις.`, vocab: [{pl: `taksówka`, el: `ταξί`, ipa: `τακ-ΣΟΥΦ-κα`},{pl: `kierowca`, el: `οδηγός`, ipa: `κιε-ΡΟΦ-τσα`},{pl: `adres`, el: `διεύθυνση`, ipa: `Α-ντρες`},{pl: `trasa`, el: `διαδρομή`, ipa: `ΤΡΑ-σα`},{pl: `cena`, el: `τιμή`, ipa: `ΤΣΕ-να`},{pl: `aplikacja`, el: `εφαρμογή`, ipa: `απ-λι-ΚΑ-τσια`},{pl: `samochód`, el: `αυτοκίνητο`, ipa: `σα-ΜΟ-χουτ`},{pl: `lotnisko`, el: `αεροδρόμιο`, ipa: `λοτ-ΝΙΣ-κο`},{pl: `centrum`, el: `κέντρο`, ipa: `ΤΣΕΝ-τρουμ`},{pl: `tutaj`, el: `εδώ`, ipa: `ΤΟΥ-ται`}], phrases: [{pl: `Na ten adres, proszę.`, el: `Σε αυτή τη διεύθυνση, παρακαλώ.`, ipa: `να τεν Α-ντρες ΠΡΟ-σε`},{pl: `Ile będzie kosztować?`, el: `Πόσο θα κοστίσει;`, ipa: `Ι-λε ΜΠΕΝ-τζιε κοστ-ΤΟ-βατς`},{pl: `Proszę zatrzymać się tutaj.`, el: `Σταματήστε εδώ, παρακαλώ.`, ipa: `ΠΡΟ-σε ζα-τσι-ΜΑΤΣ σιε ΤΟΥ-ται`},{pl: `Jadę na lotnisko.`, el: `Πηγαίνω στο αεροδρόμιο.`, ipa: `ΓΙΑ-ντε να λοτ-ΝΙΣ-κο`},{pl: `Czy to daleko?`, el: `Είναι μακριά;`, ipa: `τσι το ντα-ΛΕ-κο`},{pl: `Dziękuję, miłego dnia.`, el: `Ευχαριστώ, καλή σας μέρα.`, ipa: `τζεν-ΚΟΥ-γιε ΜΙ-βε-γκο νια`}], grammar: `Με το na χρησιμοποιείς συχνά προορισμούς όπως na lotnisko, ενώ με το do χρησιμοποιείς do centrum. Η φράση Proszę zatrzymać się tutaj είναι ευγενική και ξεκάθαρη για να ζητήσεις στάση. Το będzie σημαίνει «θα είναι» ή «θα», και εμφανίζεται σε μελλοντικές ερωτήσεις όπως Ile będzie kosztować? Σε ταξί, οι σύντομες φράσεις είναι πιο φυσικές.`, practice: [`Πες «Σε αυτή τη διεύθυνση, παρακαλώ».`,`Ρώτησε πόσο θα κοστίσει.`,`Ζήτησε να σταματήσει εδώ.`,`Πες ότι πηγαίνεις στο αεροδρόμιο.`,`Ευχαρίστησε τον οδηγό και ευχήσου καλή μέρα.`]},{day: 24, title: `Σιδηροδρομικός σταθμός και τρένα`, title_native: `Dworzec i pociągi`, focus: `Σήμερα μαθαίνεις φράσεις για τρένα και σταθμούς. Η Πολωνία έχει πολλές χρήσιμες σιδηροδρομικές συνδέσεις, οπότε αυτές οι λέξεις θα σε βοηθήσουν σε ταξίδια μεταξύ πόλεων.`, vocab: [{pl: `dworzec`, el: `σιδηροδρομικός σταθμός`, ipa: `ΝΤΒΟ-ζετς`},{pl: `pociąg`, el: `τρένο`, ipa: `ΠΟ-τσιονγκ`},{pl: `peron`, el: `αποβάθρα`, ipa: `ΠΕ-ρον`},{pl: `wagon`, el: `βαγόνι`, ipa: `ΒΑ-γκον`},{pl: `miejsce`, el: `θέση`, ipa: `ΜΙΕΪ-στσε`},{pl: `bilet`, el: `εισιτήριο`, ipa: `ΜΠΙ-λετ`},{pl: `opóźnienie`, el: `καθυστέρηση`, ipa: `ο-πουζ-ΝΙΕ-νιε`},{pl: `odjazd`, el: `αναχώρηση`, ipa: `ΟΝΤ-γιαστ`},{pl: `przyjazd`, el: `άφιξη`, ipa: `ΠΣΙ-γιαστ`},{pl: `kasa`, el: `ταμείο`, ipa: `ΚΑ-σα`}], phrases: [{pl: `Poproszę bilet do Krakowa.`, el: `Θα ήθελα εισιτήριο για Κρακοβία.`, ipa: `πο-ΠΡΟ-σε ΜΠΙ-λετ ντο ΚΡΑ-κο-βα`},{pl: `Z którego peronu?`, el: `Από ποια αποβάθρα;`, ipa: `ζ ΚΤΟΥ-ρε-γκο ΠΕ-ρο-νου`},{pl: `Czy pociąg jest opóźniony?`, el: `Είναι το τρένο καθυστερημένο;`, ipa: `τσι ΠΟ-τσιονγκ γεστ ο-πουζ-ΝΙΟ-νι`},{pl: `Mam miejsce numer pięć.`, el: `Έχω θέση αριθμός πέντε.`, ipa: `μαμ ΜΙΕΪ-στσε ΝΟΥ-μερ πιεντς`},{pl: `Gdzie jest kasa?`, el: `Πού είναι το ταμείο;`, ipa: `γκτζιε γεστ ΚΑ-σα`},{pl: `O której jest odjazd?`, el: `Τι ώρα είναι η αναχώρηση;`, ipa: `ο ΚΤΟΥ-ρει γεστ ΟΝΤ-γιαστ`}], grammar: `Για πόλεις, χρησιμοποιείς συχνά do για να πεις «προς», όπως do Krakowa ή do Warszawy. Η φράση Z którego peronu? είναι πολύ χρήσιμη στον σταθμό. Το opóźniony σημαίνει «καθυστερημένος» και θα το δεις συχνά σε πίνακες αναχωρήσεων. Μάθε καλά τις λέξεις odjazd και przyjazd, γιατί ξεχωρίζουν αναχώρηση και άφιξη.`, practice: [`Ζήτησε εισιτήριο για Κρακοβία.`,`Ρώτησε από ποια αποβάθρα φεύγει το τρένο.`,`Ρώτησε αν το τρένο έχει καθυστέρηση.`,`Πες ότι έχεις θέση αριθμός πέντε.`,`Ρώτησε τι ώρα είναι η αναχώρηση.`]},{day: 25, title: `Διαμονή σε διαμέρισμα ή Airbnb`, title_native: `Mieszkanie i wynajem krótkoterminowy`, focus: `Σήμερα μαθαίνεις λέξεις για διαμέρισμα, κλειδιά και απλά προβλήματα στη διαμονή. Είναι χρήσιμο αν μένεις σε Airbnb ή μικρό ενοικιαζόμενο διαμέρισμα στην Πολωνία.`, vocab: [{pl: `mieszkanie`, el: `διαμέρισμα`, ipa: `μιεΣΚΑ-νιε`},{pl: `klucz`, el: `κλειδί`, ipa: `κλουτς`},{pl: `drzwi`, el: `πόρτα`, ipa: `ντζβι`},{pl: `okno`, el: `παράθυρο`, ipa: `ΟΚ-νο`},{pl: `kuchnia`, el: `κουζίνα`, ipa: `ΚΟΥΧ-νια`},{pl: `łazienka`, el: `μπάνιο`, ipa: `βα-ΖΙΕΝ-κα`},{pl: `ciepła woda`, el: `ζεστό νερό`, ipa: `ΤΣΙΕΠ-βα ΒΟ-ντα`},{pl: `problem`, el: `πρόβλημα`, ipa: `ΠΡΟ-μπλεμ`},{pl: `hałas`, el: `θόρυβος`, ipa: `ΧΑ-βας`},{pl: `właściciel`, el: `ιδιοκτήτης`, ipa: `ββα-ΣΤΣΙ-τσιελ`}], phrases: [{pl: `Nie działa klucz.`, el: `Το κλειδί δεν λειτουργεί.`, ipa: `νιε ΤΖΙΑ-βα κλουτς`},{pl: `Nie ma ciepłej wody.`, el: `Δεν υπάρχει ζεστό νερό.`, ipa: `νιε μα ΤΣΙΕΠ-βει ΒΟ-ντι`},{pl: `Gdzie jest kuchnia?`, el: `Πού είναι η κουζίνα;`, ipa: `γκτζιε γεστ ΚΟΥΧ-νια`},{pl: `Mam problem z drzwiami.`, el: `Έχω πρόβλημα με την πόρτα.`, ipa: `μαμ ΠΡΟ-μπλεμ ζ ντζΒΙΑ-μι`},{pl: `Jest dużo hałasu.`, el: `Έχει πολλή φασαρία.`, ipa: `γεστ ΝΤΟΥ-ζο ΧΑ-βα-σου`},{pl: `Kiedy mogę odebrać klucz?`, el: `Πότε μπορώ να πάρω το κλειδί;`, ipa: `ΚΙΕ-ντι ΜΟ-γκε ο-ΝΤΕ-μπρατς κλουτς`}], grammar: `Η φράση Nie ma σημαίνει «δεν υπάρχει» και είναι πολύ χρήσιμη για προβλήματα, όπως Nie ma ciepłej wody. Το z σημαίνει «με», αλλά αλλάζει λίγο την επόμενη λέξη, όπως z drzwiami. Το Nie działa μπορεί να χρησιμοποιηθεί για κλειδί, Wi-Fi, τηλέφωνο ή συσκευή. Για ταξίδι, αυτές οι φράσεις λύνουν πολλά καθημερινά θέματα.`, practice: [`Πες ότι το κλειδί δεν λειτουργεί.`,`Πες ότι δεν υπάρχει ζεστό νερό.`,`Ρώτησε πού είναι η κουζίνα.`,`Πες ότι έχεις πρόβλημα με την πόρτα.`,`Ρώτησε πότε μπορείς να πάρεις το κλειδί.`]},{day: 26, title: `Στην παραλία, στο πάρκο και στη φύση`, title_native: `Na plaży, w parku i w naturze`, focus: `Σήμερα μαθαίνεις λέξεις για χαλάρωση σε πάρκα, λίμνες ή παραλίες της Βαλτικής. Θα μπορείς να μιλήσεις για βόλτες, φύση και απλές δραστηριότητες.`, vocab: [{pl: `park`, el: `πάρκο`, ipa: `παρκ`},{pl: `plaża`, el: `παραλία`, ipa: `ΠΛΑ-ζα`},{pl: `morze`, el: `θάλασσα`, ipa: `ΜΟ-ζε`},{pl: `jezioro`, el: `λίμνη`, ipa: `γε-ΖΙΟ-ρο`},{pl: `las`, el: `δάσος`, ipa: `λας`},{pl: `spacer`, el: `βόλτα`, ipa: `ΣΠΑ-τσερ`},{pl: `rower`, el: `ποδήλατο`, ipa: `ΡΟ-βερ`},{pl: `piękny`, el: `όμορφος`, ipa: `ΠΙΕΝΚ-νι`},{pl: `spokojny`, el: `ήρεμος`, ipa: `σπο-ΚΟΪ-νι`},{pl: `widok`, el: `θέα`, ipa: `ΒΙ-ντοκ`}], phrases: [{pl: `Idę na spacer.`, el: `Πηγαίνω για βόλτα.`, ipa: `Ι-ντε να ΣΠΑ-τσερ`},{pl: `To piękny widok.`, el: `Είναι όμορφη θέα.`, ipa: `το ΠΙΕΝΚ-νι ΒΙ-ντοκ`},{pl: `Gdzie jest park?`, el: `Πού είναι το πάρκο;`, ipa: `γκτζιε γεστ παρκ`},{pl: `Lubię morze.`, el: `Μου αρέσει η θάλασσα.`, ipa: `ΛΟΥ-μπιε ΜΟ-ζε`},{pl: `Czy można tu pływać?`, el: `Μπορούμε να κολυμπήσουμε εδώ;`, ipa: `τσι ΜΟΖ-να του ΠΒΙ-βατς`},{pl: `Jest bardzo spokojnie.`, el: `Είναι πολύ ήρεμα.`, ipa: `γεστ ΜΠΑΡ-τζο σπο-ΚΟΪ-νιε`}], grammar: `Το Lubię σημαίνει «μου αρέσει» ή «αγαπώ» για δραστηριότητες και πράγματα. Η φράση Idę na spacer είναι πολύ φυσική και σημαίνει «πάω για βόλτα». Το Czy można tu...? σημαίνει «επιτρέπεται εδώ;» ή «μπορούμε εδώ;». Είναι χρήσιμο όταν δεν ξέρεις αν επιτρέπεται κολύμπι, ποδήλατο ή φωτογραφίες.`, practice: [`Πες ότι πηγαίνεις για βόλτα.`,`Πες ότι η θέα είναι όμορφη.`,`Ρώτησε πού είναι το πάρκο.`,`Πες ότι σου αρέσει η θάλασσα.`,`Ρώτησε αν μπορείς να κολυμπήσεις εδώ.`]},{day: 27, title: `Πολιτισμός, ευγένεια και τοπικές συνήθειες`, title_native: `Kultura, uprzejmość i lokalne zwyczaje`, focus: `Σήμερα μαθαίνεις φράσεις που σε βοηθούν να φερθείς ευγενικά και φυσικά στην Πολωνία. Θα εξασκηθείς σε συγγνώμη, ευχαριστίες, ευχές και μικρές κοινωνικές αντιδράσεις.`, vocab: [{pl: `uprzejmy`, el: `ευγενικός`, ipa: `ου-ΠΣΕΪ-μι`},{pl: `zwyczaj`, el: `συνήθεια`, ipa: `ΖΒΙ-τσαι`},{pl: `kultura`, el: `πολιτισμός / ευγένεια`, ipa: `κουλ-ΤΟΥ-ρα`},{pl: `gość`, el: `επισκέπτης`, ipa: `γκοστς`},{pl: `gospodarz`, el: `οικοδεσπότης`, ipa: `γκο-ΣΠΟ-νταζ`},{pl: `prezent`, el: `δώρο`, ipa: `ΠΡΕ-ζεντ`},{pl: `kwiaty`, el: `λουλούδια`, ipa: `ΚΦΙΑ-τι`},{pl: `smacznego`, el: `καλή όρεξη`, ipa: `σμαΤΣΝΕ-γκο`},{pl: `na zdrowie`, el: `στην υγειά μας`, ipa: `να ΖΝΤΡΟ-βιε`},{pl: `przepraszam`, el: `συγγνώμη`, ipa: `πσε-ΠΡΑ-σαμ`}], phrases: [{pl: `Smacznego!`, el: `Καλή όρεξη!`, ipa: `σμαΤΣΝΕ-γκο`},{pl: `Na zdrowie!`, el: `Στην υγειά μας!`, ipa: `να ΖΝΤΡΟ-βιε`},{pl: `Bardzo dziękuję.`, el: `Ευχαριστώ πολύ.`, ipa: `ΜΠΑΡ-τζο τζεν-ΚΟΥ-γιε`},{pl: `To bardzo miłe.`, el: `Αυτό είναι πολύ ευγενικό.`, ipa: `το ΜΠΑΡ-τζο ΜΙ-βε`},{pl: `Przepraszam za spóźnienie.`, el: `Συγγνώμη για την καθυστέρηση.`, ipa: `πσε-ΠΡΑ-σαμ ζα σπουζ-ΝΙΕ-νιε`},{pl: `Miło cię poznać.`, el: `Χάρηκα για τη γνωριμία.`, ipa: `ΜΙ-ουο τσιε ΠΟΖ-νατς`}], grammar: `Το za σημαίνει «για» σε φράσεις όπως Przepraszam za spóźnienie. Το Smacznego λέγεται πριν ή κατά τη διάρκεια του φαγητού, όπως «καλή όρεξη». Το Na zdrowie χρησιμοποιείται και όταν πίνεις, αλλά και όταν κάποιος φτερνίζεται. Οι κοινωνικές φράσεις βοηθούν πολύ στο να φανείς ευγενικός ακόμα κι αν μιλάς λίγα πολωνικά.`, practice: [`Πες «Καλή όρεξη».`,`Πες «Στην υγειά μας».`,`Ευχαρίστησε κάποιον θερμά.`,`Ζήτησε συγγνώμη για καθυστέρηση.`,`Πες «Χάρηκα για τη γνωριμία».`]},{day: 28, title: `Προβλήματα, παράπονα και λύσεις`, title_native: `Problemy, skargi i rozwiązania`, focus: `Σήμερα μαθαίνεις πώς να εξηγείς ευγενικά ότι υπάρχει πρόβλημα. Αυτό είναι χρήσιμο σε ξενοδοχεία, εστιατόρια, καταστήματα ή μεταφορές.`, vocab: [{pl: `problem`, el: `πρόβλημα`, ipa: `ΠΡΟ-μπλεμ`},{pl: `błąd`, el: `λάθος`, ipa: `μπβοντ`},{pl: `rachunek`, el: `λογαριασμός`, ipa: `ρα-ΧΟΥ-νεκ`},{pl: `zimny`, el: `κρύος`, ipa: `ΖΙΜ-νι`},{pl: `brudny`, el: `βρώμικος`, ipa: `ΜΠΡΟΥΝΤ-νι`},{pl: `zepsuty`, el: `χαλασμένος`, ipa: `ζεπ-ΣΟΥ-τι`},{pl: `pokój`, el: `δωμάτιο`, ipa: `ΠΟ-κουι`},{pl: `zamówienie`, el: `παραγγελία`, ipa: `ζα-μου-ΒΙΕ-νιε`},{pl: `pomoc`, el: `βοήθεια`, ipa: `ΠΟ-μοτς`},{pl: `rozwiązanie`, el: `λύση`, ipa: `ροζ-βιον-ΖΑ-νιε`}], phrases: [{pl: `Mam problem.`, el: `Έχω πρόβλημα.`, ipa: `μαμ ΠΡΟ-μπλεμ`},{pl: `To nie jest moje zamówienie.`, el: `Αυτή δεν είναι η παραγγελία μου.`, ipa: `το νιε γεστ ΜΟ-γιε ζα-μου-ΒΙΕ-νιε`},{pl: `Rachunek jest zły.`, el: `Ο λογαριασμός είναι λάθος.`, ipa: `ρα-ΧΟΥ-νεκ γεστ ζβι`},{pl: `Pokój jest brudny.`, el: `Το δωμάτιο είναι βρώμικο.`, ipa: `ΠΟ-κουι γεστ ΜΠΡΟΥΝΤ-νι`},{pl: `Czy może pan pomóc?`, el: `Μπορείτε να βοηθήσετε;`, ipa: `τσι ΜΟ-ζε παν ΠΟ-μουτς`},{pl: `Chciałbym inne rozwiązanie.`, el: `Θα ήθελα άλλη λύση.`, ipa: `ΧΤΣΙΑΒ-μπιμ ΙΝ-νε ροζ-βιον-ΖΑ-νιε`}], grammar: `Το Chciałbym σημαίνει «θα ήθελα» όταν μιλά άνδρας, ενώ Chciałabym χρησιμοποιείται όταν μιλά γυναίκα. Το moje σημαίνει «δικό μου» για ουδέτερες λέξεις όπως zamówienie. Όταν κάνεις παράπονο, ξεκίνα με Mam problem ή Przepraszam, αλλά μετά πες καθαρά τι δεν πάει καλά. Η ευγένεια βοηθά πολύ, ειδικά όταν ζητάς λύση.`, practice: [`Πες ότι έχεις πρόβλημα.`,`Πες ότι η παραγγελία δεν είναι δική σου.`,`Πες ότι ο λογαριασμός είναι λάθος.`,`Πες ότι το δωμάτιο είναι βρώμικο.`,`Ζήτησε ευγενικά βοήθεια.`]},{day: 29, title: `Ανασκόπηση ταξιδιωτικών φράσεων`, title_native: `Powtórka zwrotów podróżnych`, focus: `Σήμερα κάνεις επανάληψη των πιο χρήσιμων φράσεων για πραγματικό ταξίδι στην Πολωνία. Θα συνδυάσεις χαιρετισμούς, μετακινήσεις, φαγητό, αγορές και βοήθεια.`, vocab: [{pl: `podróż`, el: `ταξίδι`, ipa: `ΠΟ-ντρουζ`},{pl: `pomoc`, el: `βοήθεια`, ipa: `ΠΟ-μοτς`},{pl: `bilet`, el: `εισιτήριο`, ipa: `ΜΠΙ-λετ`},{pl: `hotel`, el: `ξενοδοχείο`, ipa: `ΧΟ-τελ`},{pl: `restauracja`, el: `εστιατόριο`, ipa: `ρε-σταου-ΡΑ-τσια`},{pl: `centrum`, el: `κέντρο`, ipa: `ΤΣΕΝ-τρουμ`},{pl: `karta`, el: `κάρτα`, ipa: `ΚΑΡ-τα`},{pl: `adres`, el: `διεύθυνση`, ipa: `Α-ντρες`},{pl: `rezerwacja`, el: `κράτηση`, ipa: `ρε-ζερ-ΒΑ-τσια`},{pl: `dziękuję`, el: `ευχαριστώ`, ipa: `τζεν-ΚΟΥ-γιε`}], phrases: [{pl: `Dzień dobry, mam rezerwację.`, el: `Καλημέρα, έχω κράτηση.`, ipa: `τζεν ΝΤΟ-μπρι μαμ ρε-ζερ-ΒΑ-τσιε`},{pl: `Poproszę bilet do centrum.`, el: `Θα ήθελα εισιτήριο για το κέντρο.`, ipa: `πο-ΠΡΟ-σε ΜΠΙ-λετ ντο ΤΣΕΝ-τρουμ`},{pl: `Czy mogę zapłacić kartą?`, el: `Μπορώ να πληρώσω με κάρτα;`, ipa: `τσι ΜΟ-γκε ζα-ΠΒΑ-τσιτς ΚΑΡ-τομ`},{pl: `Potrzebuję pomocy.`, el: `Χρειάζομαι βοήθεια.`, ipa: `ποτ-σε-ΜΠΟΥ-γιε ΠΟ-μο-τσι`},{pl: `Gdzie jest mój hotel?`, el: `Πού είναι το ξενοδοχείο μου;`, ipa: `γκτζιε γεστ μουι ΧΟ-τελ`},{pl: `Dziękuję za pomoc.`, el: `Ευχαριστώ για τη βοήθεια.`, ipa: `τζεν-ΚΟΥ-γιε ζα ΠΟ-μοτς`}], grammar: `Σήμερα στόχος δεν είναι νέα γραμματική, αλλά η σύνδεση έτοιμων φράσεων. Στα ταξίδια, οι έτοιμες φράσεις είναι συχνά πιο χρήσιμες από την τέλεια γραμματική. Παρατήρησε πόσο συχνά επανέρχονται οι δομές Mam, Poproszę, Gdzie jest και Czy mogę. Αν τις ξέρεις καλά, μπορείς να χειριστείς πολλές καθημερινές καταστάσεις.`, practice: [`Κάνε μια πρόταση με Mam rezerwację.`,`Κάνε μια πρόταση με Poproszę bilet.`,`Ρώτησε αν μπορείς να πληρώσεις με κάρτα.`,`Ζήτησε βοήθεια.`,`Ευχαρίστησε κάποιον για τη βοήθεια.`]},{day: 30, title: `Μια πλήρης ημέρα στην Πολωνία`, title_native: `Pełny dzień w Polsce`, focus: `Σήμερα χρησιμοποιείς όλα όσα έμαθες για να περάσεις μια ολόκληρη ημέρα σε πολωνική πόλη. Θα ξεκινήσεις από το ξενοδοχείο, θα πάρεις συγκοινωνία, θα φας, θα ψωνίσεις και θα μιλήσεις με ντόπιους.`, vocab: [{pl: `rano`, el: `πρωί`, ipa: `ΡΑ-νο`},{pl: `dzień`, el: `ημέρα`, ipa: `τζεν`},{pl: `wieczór`, el: `βράδυ`, ipa: `ΒΙΕ-τσουρ`},{pl: `plan`, el: `σχέδιο`, ipa: `πλαν`},{pl: `miasto`, el: `πόλη`, ipa: `ΜΙΑΣ-το`},{pl: `jedzenie`, el: `φαγητό`, ipa: `γε-ΤΖΕ-νιε`},{pl: `zakupy`, el: `ψώνια`, ipa: `ζα-ΚΟΥ-πι`},{pl: `transport`, el: `μεταφορά`, ipa: `ΤΡΑΝΣ-πορτ`},{pl: `spotkanie`, el: `συνάντηση`, ipa: `σποτ-ΚΑ-νιε`},{pl: `powrót`, el: `επιστροφή`, ipa: `ΠΟΦ-ρουτ`}], phrases: [{pl: `Rano idę do kawiarni.`, el: `Το πρωί πάω στο καφέ.`, ipa: `ΡΑ-νο Ι-ντε ντο κα-ΒΙΑΡ-νι`},{pl: `Potem jadę tramwajem.`, el: `Μετά πηγαίνω με τραμ.`, ipa: `ΠΟ-τεμ ΓΙΑ-ντε τραμ-ΒΑ-γεμ`},{pl: `Po południu robię zakupy.`, el: `Το απόγευμα κάνω ψώνια.`, ipa: `πο πο-ΒΟΥΝΤ-νιου ΡΟ-μπιε ζα-ΚΟΥ-πι`},{pl: `Wieczorem mam kolację.`, el: `Το βράδυ έχω δείπνο.`, ipa: `βιε-ΤΣΟ-ρεμ μαμ κο-ΛΑ-τσιε`},{pl: `Wracam do hotelu.`, el: `Επιστρέφω στο ξενοδοχείο.`, ipa: `ΒΡΑ-τσαμ ντο ΧΟ-τε-λου`},{pl: `To był dobry dzień.`, el: `Ήταν καλή μέρα.`, ipa: `το μπιβ ΝΤΟΜ-μπρι τζεν`}], grammar: `Σήμερα συνδυάζεις χρονικές λέξεις όπως rano, potem, po południu και wieczorem. Αυτές βοηθούν να αφηγηθείς απλά μια ημέρα. Το idę χρησιμοποιείται για περπάτημα ή μετάβαση γενικά, ενώ jadę δηλώνει μετακίνηση με όχημα. Με λίγες τέτοιες λέξεις μπορείς να περιγράψεις σχέδια, εμπειρίες και καθημερινές κινήσεις.`, practice: [`Πες τι κάνεις το πρωί χρησιμοποιώντας Rano.`,`Πες ότι μετά πηγαίνεις με τραμ.`,`Πες ότι το απόγευμα κάνεις ψώνια.`,`Πες ότι επιστρέφεις στο ξενοδοχείο.`,`Περιέγραψε μια πλήρη ημέρα στην Πολωνία με τέσσερις σύντομες πολωνικές προτάσεις.`]}];

var CONVERSATIONS_EL_PL = [{id: 1, title: `Παραγγελία σε καφέ`, scene: `Βρίσκεσαι σε ένα μικρό καφέ στην Κρακοβία κοντά στην κεντρική πλατεία. Θέλεις να παραγγείλεις καφέ και ένα κομμάτι γλυκό με ευγενικό τρόπο.`, lines: [{who: `them`, pl: `Dzień dobry, co podać?`, el: `Καλημέρα, τι να σας φέρω;`},{who: `you`, pl: `Dzień dobry, poproszę kawę.`, el: `Καλημέρα, θα ήθελα έναν καφέ.`},{who: `them`, pl: `Małą czy dużą?`, el: `Μικρή ή μεγάλη;`},{who: `you`, pl: `Dużą, proszę.`, el: `Μεγάλη, παρακαλώ.`},{who: `them`, pl: `Z mlekiem czy bez mleka?`, el: `Με γάλα ή χωρίς γάλα;`},{who: `you`, pl: `Z mlekiem, ale bez cukru.`, el: `Με γάλα, αλλά χωρίς ζάχαρη.`},{who: `them`, pl: `Czy coś jeszcze?`, el: `Κάτι άλλο;`},{who: `you`, pl: `Czy macie ciasto?`, el: `Έχετε γλυκό;`},{who: `them`, pl: `Tak, mamy sernik.`, el: `Ναι, έχουμε τσιζκέικ.`},{who: `you`, pl: `Poproszę sernik.`, el: `Θα ήθελα τσιζκέικ.`},{who: `them`, pl: `Razem dwadzieścia złotych.`, el: `Μαζί είκοσι ζλότι.`},{who: `you`, pl: `Dziękuję, płacę kartą.`, el: `Ευχαριστώ, πληρώνω με κάρτα.`}]},{id: 2, title: `Check-in σε ξενοδοχείο`, scene: `Φτάνεις σε ξενοδοχείο στη Βαρσοβία μετά από πτήση. Πηγαίνεις στη ρεσεψιόν για να κάνεις check-in και να ρωτήσεις για το πρωινό.`, lines: [{who: `them`, pl: `Dzień dobry, witamy w hotelu.`, el: `Καλημέρα, καλώς ήρθατε στο ξενοδοχείο.`},{who: `you`, pl: `Dzień dobry, mam rezerwację.`, el: `Καλημέρα, έχω κράτηση.`},{who: `them`, pl: `Na jakie nazwisko?`, el: `Σε ποιο επίθετο;`},{who: `you`, pl: `Na nazwisko Papadopoulos.`, el: `Στο όνομα Παπαδόπουλος.`},{who: `them`, pl: `Poproszę paszport.`, el: `Το διαβατήριο, παρακαλώ.`},{who: `you`, pl: `Proszę, to mój paszport.`, el: `Ορίστε, αυτό είναι το διαβατήριό μου.`},{who: `them`, pl: `Pokój jest gotowy.`, el: `Το δωμάτιο είναι έτοιμο.`},{who: `you`, pl: `Czy śniadanie jest w cenie?`, el: `Είναι το πρωινό στην τιμή;`},{who: `them`, pl: `Tak, od siódmej do dziesiątej.`, el: `Ναι, από τις επτά έως τις δέκα.`},{who: `you`, pl: `Dziękuję, gdzie jest winda?`, el: `Ευχαριστώ, πού είναι το ασανσέρ;`},{who: `them`, pl: `Po prawej stronie.`, el: `Στη δεξιά πλευρά.`},{who: `you`, pl: `Dziękuję bardzo.`, el: `Ευχαριστώ πολύ.`}]},{id: 3, title: `Ζητώντας οδηγίες στην παλιά πόλη`, scene: `Περπατάς στην παλιά πόλη της Βαρσοβίας και ψάχνεις το Βασιλικό Κάστρο. Σταματάς έναν περαστικό και ζητάς οδηγίες ευγενικά.`, lines: [{who: `you`, pl: `Przepraszam, gdzie jest zamek?`, el: `Με συγχωρείτε, πού είναι το κάστρο;`},{who: `them`, pl: `Zamek Królewski?`, el: `Το Βασιλικό Κάστρο;`},{who: `you`, pl: `Tak, Zamek Królewski.`, el: `Ναι, το Βασιλικό Κάστρο.`},{who: `them`, pl: `Proszę iść prosto.`, el: `Πηγαίνετε ευθεία.`},{who: `you`, pl: `Prosto?`, el: `Ευθεία;`},{who: `them`, pl: `Tak, potem w prawo.`, el: `Ναι, μετά δεξιά.`},{who: `you`, pl: `Czy to daleko?`, el: `Είναι μακριά;`},{who: `them`, pl: `Nie, to bardzo blisko.`, el: `Όχι, είναι πολύ κοντά.`},{who: `you`, pl: `Ile minut pieszo?`, el: `Πόσα λεπτά με τα πόδια;`},{who: `them`, pl: `Około pięć minut.`, el: `Περίπου πέντε λεπτά.`},{who: `you`, pl: `Dziękuję za pomoc.`, el: `Ευχαριστώ για τη βοήθεια.`},{who: `them`, pl: `Proszę bardzo.`, el: `Παρακαλώ πολύ.`}]},{id: 4, title: `Δείπνο σε εστιατόριο`, scene: `Μπαίνεις σε εστιατόριο στο Γκντανσκ και θέλεις τραπέζι για δύο. Ρωτάς για το μενού, παραγγέλνεις pierogi και ζητάς τον λογαριασμό.`, lines: [{who: `them`, pl: `Dobry wieczór, ile osób?`, el: `Καλησπέρα, πόσα άτομα;`},{who: `you`, pl: `Stolik dla dwóch osób, proszę.`, el: `Τραπέζι για δύο άτομα, παρακαλώ.`},{who: `them`, pl: `Proszę tędy.`, el: `Παρακαλώ από εδώ.`},{who: `you`, pl: `Dziękuję, poproszę menu.`, el: `Ευχαριστώ, θα ήθελα το μενού.`},{who: `them`, pl: `Oczywiście, proszę.`, el: `Βεβαίως, ορίστε.`},{who: `you`, pl: `Co pani poleca?`, el: `Τι προτείνετε;`},{who: `them`, pl: `Polecam pierogi z serem.`, el: `Προτείνω πιερόγκι με τυρί.`},{who: `you`, pl: `Poproszę pierogi i wodę.`, el: `Θα ήθελα πιερόγκι και νερό.`},{who: `them`, pl: `Czy coś jeszcze?`, el: `Κάτι άλλο;`},{who: `you`, pl: `Nie, dziękuję.`, el: `Όχι, ευχαριστώ.`},{who: `them`, pl: `Smacznego!`, el: `Καλή όρεξη!`},{who: `you`, pl: `Dziękuję, rachunek proszę.`, el: `Ευχαριστώ, τον λογαριασμό παρακαλώ.`}]},{id: 5, title: `Αγορά εισιτηρίου για τραμ`, scene: `Βρίσκεσαι σε σταθμό τραμ στο Πόζναν και θέλεις να πας στο κέντρο. Ρωτάς ποιο τραμ να πάρεις και αγοράζεις εισιτήριο.`, lines: [{who: `you`, pl: `Przepraszam, gdzie jest przystanek tramwajowy?`, el: `Με συγχωρείτε, πού είναι η στάση του τραμ;`},{who: `them`, pl: `Tutaj, po lewej stronie.`, el: `Εδώ, στην αριστερή πλευρά.`},{who: `you`, pl: `Który tramwaj jedzie do centrum?`, el: `Ποιο τραμ πηγαίνει στο κέντρο;`},{who: `them`, pl: `Tramwaj numer pięć.`, el: `Το τραμ νούμερο πέντε.`},{who: `you`, pl: `Dziękuję, gdzie kupię bilet?`, el: `Ευχαριστώ, πού θα αγοράσω εισιτήριο;`},{who: `them`, pl: `W automacie obok przystanku.`, el: `Στο μηχάνημα δίπλα στη στάση.`},{who: `you`, pl: `Czy mogę zapłacić kartą?`, el: `Μπορώ να πληρώσω με κάρτα;`},{who: `them`, pl: `Tak, można kartą.`, el: `Ναι, γίνεται με κάρτα.`},{who: `you`, pl: `Czy to jest następny tramwaj?`, el: `Είναι αυτό το επόμενο τραμ;`},{who: `them`, pl: `Tak, to tramwaj do centrum.`, el: `Ναι, αυτό είναι το τραμ για το κέντρο.`},{who: `you`, pl: `Dziękuję bardzo.`, el: `Ευχαριστώ πολύ.`},{who: `them`, pl: `Nie ma za co.`, el: `Δεν κάνει τίποτα.`}]},{id: 6, title: `Αγορά σουβενίρ`, scene: `Είσαι σε μικρό κατάστημα με σουβενίρ στην Κρακοβία. Θέλεις να ρωτήσεις τιμή, να πληρώσεις με κάρτα και να πάρεις τσάντα.`, lines: [{who: `them`, pl: `Dzień dobry, mogę pomóc?`, el: `Καλημέρα, μπορώ να βοηθήσω;`},{who: `you`, pl: `Dzień dobry, ile to kosztuje?`, el: `Καλημέρα, πόσο κοστίζει αυτό;`},{who: `them`, pl: `To kosztuje trzydzieści złotych.`, el: `Αυτό κοστίζει τριάντα ζλότι.`},{who: `you`, pl: `Czy to jest lokalne?`, el: `Είναι τοπικό αυτό;`},{who: `them`, pl: `Tak, to polska pamiątka.`, el: `Ναι, είναι πολωνικό σουβενίρ.`},{who: `you`, pl: `Wezmę to.`, el: `Θα το πάρω.`},{who: `them`, pl: `Czy potrzebuje pan torby?`, el: `Χρειάζεστε τσάντα;`},{who: `you`, pl: `Tak, poproszę torbę.`, el: `Ναι, θα ήθελα τσάντα.`},{who: `them`, pl: `Gotówką czy kartą?`, el: `Με μετρητά ή με κάρτα;`},{who: `you`, pl: `Kartą, proszę.`, el: `Με κάρτα, παρακαλώ.`},{who: `them`, pl: `Dziękuję, oto paragon.`, el: `Ευχαριστώ, ορίστε η απόδειξη.`},{who: `you`, pl: `Dziękuję, do widzenia.`, el: `Ευχαριστώ, αντίο.`}]},{id: 7, title: `Στο φαρμακείο`, scene: `Δεν αισθάνεσαι καλά και μπαίνεις σε φαρμακείο στη Βαρσοβία. Θέλεις να εξηγήσεις ότι έχεις πονοκέφαλο και να ρωτήσεις αν χρειάζεται συνταγή.`, lines: [{who: `them`, pl: `Dzień dobry, słucham.`, el: `Καλημέρα, σας ακούω.`},{who: `you`, pl: `Dzień dobry, boli mnie głowa.`, el: `Καλημέρα, με πονάει το κεφάλι.`},{who: `them`, pl: `Czy ma pan gorączkę?`, el: `Έχετε πυρετό;`},{who: `you`, pl: `Nie, nie mam gorączki.`, el: `Όχι, δεν έχω πυρετό.`},{who: `them`, pl: `Potrzebuje pan tabletek przeciwbólowych?`, el: `Χρειάζεστε παυσίπονα χάπια;`},{who: `you`, pl: `Tak, proszę.`, el: `Ναι, παρακαλώ.`},{who: `them`, pl: `Czy ma pan alergię?`, el: `Έχετε αλλεργία;`},{who: `you`, pl: `Mam alergię na orzechy.`, el: `Έχω αλλεργία στους ξηρούς καρπούς.`},{who: `them`, pl: `To nie jest problem.`, el: `Αυτό δεν είναι πρόβλημα.`},{who: `you`, pl: `Czy potrzebuję recepty?`, el: `Χρειάζομαι συνταγή;`},{who: `them`, pl: `Nie, recepta nie jest potrzebna.`, el: `Όχι, δεν χρειάζεται συνταγή.`},{who: `you`, pl: `Dziękuję za pomoc.`, el: `Ευχαριστώ για τη βοήθεια.`}]},{id: 8, title: `Μικρή κουβέντα με ντόπιο`, scene: `Κάθεσαι σε παγκάκι σε πάρκο στο Βρότσλαβ και ένας ντόπιος σχολιάζει τον καιρό. Κάνετε μια απλή, φιλική κουβέντα για την πόλη και το ταξίδι σου.`, lines: [{who: `them`, pl: `Ładna pogoda dzisiaj.`, el: `Ωραίος καιρός σήμερα.`},{who: `you`, pl: `Tak, jest bardzo przyjemnie.`, el: `Ναι, είναι πολύ ευχάριστα.`},{who: `them`, pl: `Jest pan turystą?`, el: `Είστε τουρίστας;`},{who: `you`, pl: `Tak, jestem z Grecji.`, el: `Ναι, είμαι από την Ελλάδα.`},{who: `them`, pl: `Pierwszy raz w Polsce?`, el: `Πρώτη φορά στην Πολωνία;`},{who: `you`, pl: `Tak, jestem tu pierwszy raz.`, el: `Ναι, είμαι εδώ πρώτη φορά.`},{who: `them`, pl: `Jak się panu podoba Wrocław?`, el: `Πώς σας φαίνεται το Βρότσλαβ;`},{who: `you`, pl: `Bardzo mi się podoba.`, el: `Μου αρέσει πολύ.`},{who: `them`, pl: `To piękne miasto.`, el: `Είναι όμορφη πόλη.`},{who: `you`, pl: `Tak, ludzie są bardzo mili.`, el: `Ναι, οι άνθρωποι είναι πολύ ευγενικοί.`},{who: `them`, pl: `Miłego pobytu!`, el: `Καλή διαμονή!`},{who: `you`, pl: `Dziękuję, miło było porozmawiać.`, el: `Ευχαριστώ, χάρηκα που μιλήσαμε.`}]}];